export interface GlossaryTerm {
  term: string;
  definition: string;
  example?: string;
}

export const glossaryData: Record<string, GlossaryTerm[]> = {
  A: [
    { term: "Abstract", definition: "A summary of all recorded deeds, mortgages, and leases affecting the title to a piece of land.", example: "Before closing, your title company reviews the abstract to verify no outstanding claims exist against the property." },
    { term: "Abstract Plant", definition: "A geographically indexed collection of title records maintained by a title company, used to compile abstracts of title efficiently without searching county records from scratch each time.", example: "Title companies with their own abstract plant can complete title searches faster and more accurately than those relying solely on county records." },
    { term: "Abstracting", definition: "The process of making and compiling an abstract of title.", example: "The abstracting process may reveal a 20-year-old lien that the seller didn't know existed." },
    { term: "Acceleration", definition: "The right of a lender to demand immediate repayment of the entire outstanding loan balance upon the occurrence of a specific event, such as a missed payment or sale of the property.", example: "After three missed payments, the bank invoked the acceleration provision and demanded the full $240,000 remaining balance." },
    { term: "Acceleration Clause", definition: "A provision in a mortgage that allows the lender to demand the entire balance due immediately if the borrower defaults on payments or violates other loan terms.", example: "If you miss three mortgage payments, the acceleration clause lets the bank demand the full remaining balance at once." },
    { term: "Acre", definition: "A unit of land measurement equal to 43,560 square feet, or roughly the size of a football field without the end zones.", example: "In suburban areas, a typical residential lot might be a quarter acre to half an acre, while rural properties can span dozens of acres." },
    { term: "Actual Cash Value", definition: "A method of valuing insured property based on replacement cost minus depreciation. Pays less than replacement cost coverage because it accounts for the age and wear of the item.", example: "If your 10-year-old roof is destroyed by a storm, actual cash value coverage pays what the roof is worth today after depreciation, not what a new roof costs." },
    { term: "Adjudication", definition: "A formal legal judgment or decision by a court regarding the rights of parties in a dispute, including disputes over property ownership or boundaries.", example: "The boundary dispute between the two homeowners went to court for adjudication, and the judge ruled based on the original survey." },
    { term: "Adjustable-Rate Mortgage (ARM)", definition: "A mortgage with an interest rate that changes periodically based on a financial index. The rate is typically fixed for an initial period (3, 5, 7, or 10 years) and then adjusts annually.", example: "A 5/1 ARM means your rate is fixed for 5 years, then adjusts every year after that — which could increase or decrease your monthly payment." },
    { term: "Adverse Possession", definition: "Unauthorized occupation of another's land which, if continued for a fixed period of time, may grant the occupier legal title.", example: "A neighbor who maintained a strip of your property for 15+ years could claim adverse possession — title insurance protects against this." },
    { term: "Affidavit", definition: "A written statement made under oath, typically used in real estate to confirm facts about the property, identity, or transaction.", example: "At closing, you may sign an affidavit of occupancy confirming you intend to use the property as your primary residence." },
    { term: "ALTA", definition: "American Land Title Association — the national trade organization for the title insurance industry. ALTA develops industry standards, best practices, and policy forms used across the country.", example: "Look for ALTA member companies when choosing a title provider — they follow industry best practices for security and consumer protection." },
    { term: "Amortization", definition: "Paying off an existing debt through regular partial payments of principal and interest over a set period. Early payments are mostly interest; later payments are mostly principal.", example: "A 30-year mortgage amortizes your loan so each monthly payment covers both principal and interest — but in year one, roughly 80% goes to interest." },
    { term: "Amortization Schedule", definition: "A detailed table showing each mortgage payment broken down into principal and interest, the remaining balance after each payment, and the cumulative interest paid over the life of the loan.", example: "Your amortization schedule shows that over 30 years on a $300,000 loan at 6.5%, you'll pay roughly $382,000 in interest on top of the original balance." },
    { term: "Annual Income", definition: "The total amount of money earned in a year before taxes and deductions. Lenders use annual income to calculate qualifying ratios for mortgage approval.", example: "Lenders will ask for proof of annual income via W-2s, tax returns, and pay stubs to determine how much mortgage you can afford." },
    { term: "Annual Percentage Rate (APR)", definition: "The total yearly cost of a mortgage expressed as a percentage, including the interest rate, points, mortgage insurance, and certain fees. The APR is always equal to or higher than the interest rate.", example: "Your Loan Estimate will show the APR, which includes fees and gives you a true cost comparison between lenders — always compare APRs, not just rates." },
    { term: "Appraisal", definition: "A professional estimate of a property's market value performed by a licensed appraiser. Lenders require an appraisal to confirm the property is worth at least the purchase price.", example: "Your lender orders an appraisal ($400-$600) to confirm the home is worth the purchase price before approving your mortgage." },
    { term: "Appraised Value", definition: "The dollar value assigned to a property by a licensed appraiser after analyzing comparable sales, property condition, and local market data.", example: "If the appraised value comes in lower than your offer price, you may need to renegotiate or bring additional cash to closing." },
    { term: "Appreciation", definition: "An increase in the value of a property over time due to market conditions, improvements, or inflation.", example: "If your home appreciates 4% annually, a $350,000 home could be worth roughly $425,000 in five years, building your equity." },
    { term: "Arbitration", definition: "A method of resolving disputes outside of court where an impartial third party (the arbitrator) hears both sides and makes a binding decision.", example: "Some real estate contracts include an arbitration clause requiring disputes to be resolved by an arbitrator rather than through a lawsuit." },
    { term: "Assessed Value", definition: "The value assigned to a property by a local tax assessor for the purpose of calculating property taxes. Often differs from the market value or appraised value.", example: "Your county might assess your home at $280,000 for tax purposes even though the market value is $350,000 — the assessment determines your tax bill." },
    { term: "Assessor", definition: "A local government official who determines the assessed value of properties within a jurisdiction for the purpose of levying property taxes.", example: "The county assessor reassesses property values periodically, which can cause your property tax bill to increase if values in your area have risen." },
    { term: "Asset Depletion Loan", definition: "A mortgage qualification method that allows borrowers to use liquid assets (savings, investments, retirement accounts) instead of traditional income to qualify, calculated by dividing total assets over the loan term.", example: "A retiree with $1.2 million in investments but limited monthly income might qualify for a mortgage using asset depletion, where the lender treats assets as equivalent to monthly income." },
    { term: "Assumable Mortgage", definition: "A mortgage that allows a new buyer to take over the seller's existing loan terms, including the interest rate and remaining balance.", example: "In a rising rate environment, an assumable mortgage at 3.5% could save the buyer thousands compared to current market rates." },
    { term: "Assumption Clause", definition: "A provision in a mortgage that allows or prohibits a new buyer from assuming (taking over) the existing mortgage when the property is sold.", example: "FHA and VA loans typically have an assumption clause that allows a qualified buyer to take over the loan, while most conventional loans prohibit assumption." },
    { term: "Attorney Opinion Letter", definition: "A written statement from a licensed attorney certifying the status of a property's title after reviewing public records, used in some states as an alternative to title insurance.", example: "In some states, buyers can obtain an attorney opinion letter instead of a full title insurance policy, though it offers less protection against hidden defects." },
    { term: "Automated Underwriting System (AUS)", definition: "A computerized system (such as Fannie Mae's Desktop Underwriter or Freddie Mac's Loan Prospector) that evaluates a mortgage application and issues a recommendation to approve, refer, or deny the loan.", example: "Your lender runs your application through an AUS within minutes of submission — an 'approve/eligible' finding speeds up the underwriting process significantly." },
    { term: "Automated Valuation Model (AVM)", definition: "A technology-based tool that uses data from public records, MLS listings, and algorithms to estimate a property's market value without a physical inspection.", example: "Some lenders use an AVM for refinances or HELOCs instead of a full appraisal, saving the borrower $400-$600 and speeding up the process." },
    { term: "Assignment", definition: "The transfer of a mortgage, contract, or other interest from one party to another. When your mortgage is assigned (sold) to a new servicer, your loan terms remain the same.", example: "Your original lender may assign your mortgage to another company within weeks of closing — your loan terms don't change, but you'll send payments to the new servicer." },
    { term: "As-Is", definition: "A property sold in its current condition without any obligation from the seller to make repairs or improvements. Buyers can still perform inspections but the seller is not required to fix anything.", example: "Buying a home 'as-is' doesn't mean you skip the inspection — it means the seller won't make repairs, so factor estimated repair costs into your offer price." },
    { term: "Abstract of Judgment", definition: "A summary of a court judgment that, when recorded in the county records, creates a lien against any real property owned by the debtor in that county.", example: "If the seller has an abstract of judgment recorded against them, the resulting lien must be paid off or released before the title company will issue clear title." },
  ],
  B: [
    { term: "Back-to-Back Closing", definition: "Two closings on the same property occurring on the same day — typically when an investor buys a property and immediately resells it, or when a homeowner simultaneously sells one home and buys another.", example: "In a back-to-back closing, the funds from the morning sale of your current home are used to close on your new home that afternoon." },
    { term: "Balloon Mortgage", definition: "A mortgage with relatively small monthly payments for a fixed period, followed by a large lump-sum payment (the 'balloon') due at the end of the term.", example: "A 7-year balloon mortgage might have low payments for 7 years, then require the entire remaining balance — often $200,000+ — in one payment." },
    { term: "Bank Statement Loan", definition: "A type of non-QM mortgage where the borrower qualifies using 12-24 months of bank statements instead of tax returns or W-2s, designed for self-employed borrowers whose tax deductions reduce their reported income.", example: "A self-employed freelancer earning $150,000 but reporting $80,000 after deductions might qualify for a larger mortgage with a bank statement loan." },
    { term: "Basic Rate", definition: "The standard rate charged to title insurance consumers who do not qualify for reduced rates such as reissue or refinance rates." },
    { term: "Basis Point", definition: "One-hundredth of one percentage point (0.01%). Used to describe small changes in interest rates or fees.", example: "A rate increase of 25 basis points means your rate went up by 0.25% — on a $300,000 loan, that's roughly $45 more per month." },
    { term: "Beneficiary", definition: "The person or entity entitled to receive benefits from a trust, will, insurance policy, or deed of trust. In a deed of trust, the beneficiary is the lender.", example: "On your deed of trust, the lender is listed as the beneficiary — meaning they hold the right to foreclose if you default on the loan." },
    { term: "Binder (Insurance)", definition: "A temporary insurance agreement providing coverage until a permanent policy is issued. In title insurance, a binder is a commitment to insure. In homeowner's insurance, it is proof of coverage.", example: "Your lender requires an insurance binder before closing to confirm your homeowner's policy is in effect as of the closing date." },
    { term: "Biweekly Payment", definition: "A mortgage payment plan where the borrower makes half the monthly payment every two weeks, resulting in 26 half-payments (13 full payments) per year instead of 12, accelerating payoff.", example: "Switching to biweekly payments on a $300,000 mortgage at 6.5% can shave about 5 years off the loan and save over $60,000 in interest." },
    { term: "Breach", definition: "A violation of a contractual obligation or legal duty. In real estate, a breach of contract occurs when one party fails to perform their obligations under the purchase agreement.", example: "If the seller refuses to make agreed-upon repairs, that may constitute a breach of contract, giving you the right to cancel or seek damages." },
    { term: "Bridge Loan", definition: "A short-term loan that allows homeowners to use their current home's equity as a down payment on a new home before the current home sells.", example: "A bridge loan lets you make an offer on your next home without waiting for your current home to close — but carries higher interest rates." },
    { term: "Broker", definition: "An agent who negotiates sales or purchases of property for a fee or commission. A mortgage broker shops multiple lenders on your behalf.", example: "A mortgage broker can compare rates from 10+ lenders simultaneously, potentially finding you a better deal than going to one bank." },
    { term: "Broker Price Opinion (BPO)", definition: "An estimate of property value provided by a real estate broker, typically less detailed than a full appraisal.", example: "Some lenders accept a BPO instead of a full appraisal for certain refinance transactions, saving the borrower $200-$400." },
    { term: "Building Code", definition: "Local government regulations that set minimum standards for construction, renovation, plumbing, electrical, and structural safety of buildings.", example: "Before purchasing a flipped home, verify that renovations were done to building code — unpermitted work can create problems with insurance, financing, and resale." },
    { term: "Building Permit", definition: "A government authorization required before constructing, renovating, or making significant changes to a building, ensuring the work complies with building codes and zoning regulations.", example: "Always ask the seller for copies of building permits for any renovations — unpermitted additions can be required to be removed or brought to code at your expense." },
    { term: "Buydown", definition: "A financing technique where the borrower pays an upfront fee to reduce the interest rate for the first few years of the loan (temporary buydown) or the entire term (permanent buydown).", example: "A 2-1 buydown reduces your rate by 2% in year one and 1% in year two — the seller or builder sometimes pays for this as an incentive." },
    { term: "Buyer's Agent", definition: "A real estate agent who represents the buyer's interests in a transaction, helping find properties, negotiate offers, and navigate closing.", example: "Your buyer's agent works for you — they'll research comparable sales, write your offer, negotiate repairs, and guide you to closing." },
    { term: "Buyer's Market", definition: "A real estate market condition where there are more homes for sale than buyers, giving purchasers more negotiating power on price, concessions, and terms.", example: "In a buyer's market with 6+ months of inventory, you may be able to negotiate seller concessions, below-asking prices, and longer inspection periods." },
    { term: "Blanket Mortgage", definition: "A single mortgage that covers two or more parcels of real estate, commonly used by developers who purchase and develop multiple lots under one loan.", example: "A builder might use a blanket mortgage to finance 20 lots in a subdivision, with a partial release clause allowing individual lots to be sold as homes are completed." },
    { term: "Boundary Survey", definition: "A survey that establishes the exact property lines and corners of a parcel of land based on the legal description in the deed, identifying any encroachments or discrepancies.", example: "A boundary survey confirmed the neighbor's shed was 2 feet over the property line — this had to be resolved before the title company would insure the property." },
  ],
  C: [
    { term: "Cap", definition: "A limit on how much an adjustable-rate mortgage's interest rate or payment can change at each adjustment period or over the life of the loan.", example: "A 2/6 cap means your ARM rate can't increase more than 2% per adjustment or more than 6% total over the life of the loan." },
    { term: "Capitalization Rate (Cap Rate)", definition: "A measure of a property's investment return, calculated by dividing the net operating income by the property's market value. Used primarily for investment properties.", example: "A rental property generating $24,000 in net annual income with a value of $300,000 has a cap rate of 8% — higher cap rates generally mean higher risk and return." },
    { term: "Cash Flow", definition: "The net amount of money coming in and going out from a rental or investment property after all expenses (mortgage, taxes, insurance, maintenance) are paid.", example: "Positive cash flow of $300/month means your rental income exceeds all property expenses by $300, providing passive income." },
    { term: "Cash Reserves", definition: "Liquid assets a borrower has available after closing, typically measured in months of mortgage payments. Many lenders require 2-6 months of reserves.", example: "Your lender may require you to have 3 months of cash reserves ($6,000 if your PITI is $2,000/month) in the bank after closing." },
    { term: "Cash-Out Refinance", definition: "A refinancing transaction in which the new mortgage is larger than the existing one, allowing the borrower to receive the difference in cash to use for any purpose.", example: "If you owe $200,000 on a home worth $400,000, a cash-out refinance for $280,000 puts $80,000 in your pocket — but increases your mortgage balance." },
    { term: "Caveat Emptor", definition: "A Latin phrase meaning 'let the buyer beware.' A legal principle that places the burden on the buyer to perform due diligence before purchasing, though modern disclosure laws have shifted much of this responsibility to the seller.", example: "While caveat emptor still applies in some states for 'as-is' sales, most states now require sellers to disclose known defects." },
    { term: "Certificate of Compliance", definition: "A document issued by a local government confirming that a property meets applicable building codes, zoning regulations, or other municipal requirements.", example: "Some municipalities require a certificate of compliance before a home can be sold, verifying that the property meets current safety standards." },
    { term: "Certificate of Occupancy (CO)", definition: "A document issued by a local government certifying that a building complies with building codes and is safe for occupancy. Required for new construction and major renovations.", example: "Your lender will not fund a new construction loan until the builder obtains the certificate of occupancy confirming the home is safe to live in." },
    { term: "Certificate of Title", definition: "A written attorney opinion stating who holds title to a property, based on examination of an abstract of title." },
    { term: "Chain of Title", definition: "The complete history of ownership transfers for a property, from the original grant through every subsequent deed, forming an unbroken chain to the current owner.", example: "A break in the chain of title — like a missing signature from 1987 — can cloud your ownership rights. Title insurance protects against this." },
    { term: "Chattel", definition: "Personal property that is movable, as opposed to real property which is permanently attached to land. Appliances, furniture, and window treatments may be considered chattel.", example: "The purchase contract should specify which chattel is included in the sale — the refrigerator and washer/dryer are negotiable items, not part of the real property." },
    { term: "Clear to Close (CTC)", definition: "The final approval from your lender's underwriter confirming all conditions have been met and the loan is ready to fund. This is the green light for closing.", example: "Once you receive 'clear to close,' your lender has reviewed everything — income, credit, appraisal, title — and is ready to issue your mortgage." },
    { term: "Closing", definition: "Also called 'settlement' — the final step in a real estate transaction where documents are signed, funds disbursed, and ownership transferred from seller to buyer.", example: "At closing, you'll sign 50-100+ pages of documents, provide your down payment and closing costs, and receive the keys to your new home." },
    { term: "Closing Agent", definition: "The person who conducts the closing — a title agent, escrow officer, settlement agent, or attorney depending on state requirements.", example: "Your closing agent coordinates all parties, prepares documents, collects and disburses funds, and records the deed with the county." },
    { term: "Closing Costs", definition: "Fees and expenses — beyond the purchase price — that buyers and sellers pay to complete a real estate transaction. Typically 2-5% of the purchase price for buyers.", example: "On a $350,000 home, closing costs typically run $7,000-$17,500 and include lender fees, title insurance, appraisal, recording fees, and prepaid expenses." },
    { term: "Closing Disclosure (CD)", definition: "A five-page standardized document provided at least three business days before closing that details all final mortgage terms, projected payments, and itemized closing costs.", example: "Compare your Closing Disclosure line-by-line to your Loan Estimate — fees that increased beyond their tolerance threshold must be refunded by the lender." },
    { term: "Closing Protection Letter", definition: "A document issued by a title insurance underwriter to the lender guaranteeing that the closing agent will follow the lender's instructions for handling funds and documents.", example: "The closing protection letter protects the lender (and sometimes the buyer) if the closing agent mishandles funds or fails to follow instructions." },
    { term: "Cloud on Title", definition: "Any irregularity, possible claim, lien, or encumbrance that could potentially affect or impair the title to a property.", example: "An unreleased mortgage from a previous owner creates a cloud on title that must be cleared before the title company will insure the property." },
    { term: "Co-Borrower", definition: "A person who applies for and shares responsibility for a mortgage loan equally with the primary borrower. Both borrowers' income, assets, and credit are used to qualify.", example: "Adding your spouse as a co-borrower lets the lender count both incomes when qualifying, potentially allowing you to afford a more expensive home." },
    { term: "Co-Signer", definition: "A person who signs a mortgage note along with the primary borrower, agreeing to repay the loan if the borrower defaults, but who does not hold an ownership interest in the property.", example: "A parent co-signing their child's mortgage takes on full legal responsibility for repayment if the child defaults, even though the parent doesn't own the home." },
    { term: "Commitment Fee", definition: "A fee charged by a title company or lender for issuing a commitment — a promise to provide title insurance or a mortgage loan under specified terms.", example: "The title company may charge a commitment fee of $100-$300 when issuing the title commitment, which may be credited toward the final policy premium." },
    { term: "Common Area", definition: "Portions of a property that are shared by all owners or residents, such as lobbies, hallways, pools, gyms, and landscaped areas in condominiums or planned communities.", example: "Your HOA dues cover maintenance of common areas including the pool, clubhouse, and landscaping throughout the subdivision." },
    { term: "Comparable Sales (Comps)", definition: "Recently sold properties similar to the subject property in size, location, condition, and features. Used by appraisers and agents to determine market value.", example: "Your agent will pull 3-6 comps within a 1-mile radius to help you determine a fair offer price for the home." },
    { term: "Compound Interest", definition: "Interest calculated on both the initial principal and the accumulated interest from previous periods. Unlike simple interest, compound interest grows exponentially over time.", example: "Credit card debt compounds daily, making it expensive to carry balances — paying off credit cards before applying for a mortgage improves both your DTI and credit score." },
    { term: "Concurrent Closing", definition: "Multiple real estate transactions closing simultaneously, often involving the same property or parties, such as when a seller's closing and a buyer's closing happen at the same time using the same funds.", example: "In a concurrent closing, the buyer's funds from their lender go to pay off the seller's mortgage and fund the seller's purchase of their next home, all on the same day." },
    { term: "Condominium", definition: "A form of ownership where the buyer owns an individual unit within a multi-unit building or complex, plus a shared interest in common areas like lobbies, grounds, and amenities.", example: "When you buy a condo, you own everything inside your unit's walls, but the building structure, roof, and common areas are collectively owned by all unit owners." },
    { term: "Community Property", definition: "A form of property ownership in certain states where any property acquired during marriage is equally owned by both spouses, regardless of who earned the income or whose name is on the title.", example: "In community property states like California and Texas, both spouses must sign the deed even if only one spouse's name is on the mortgage." },
    { term: "Conforming Loan Limit", definition: "The maximum loan amount that Fannie Mae and Freddie Mac will purchase or guarantee, set annually by the Federal Housing Finance Agency (FHFA). Loans above this limit are considered jumbo loans.", example: "For 2025, the conforming loan limit is $806,500 in most areas and up to $1,209,750 in high-cost areas — loans above these amounts require jumbo financing." },
    { term: "Consideration", definition: "Something of value exchanged between parties to form a legally binding contract. In real estate, the consideration is typically money paid by the buyer for the property.", example: "Every valid deed states the consideration — even if nominal, like 'for $10 and other good and valuable consideration' — to establish a legally binding transfer." },
    { term: "Construction Loan", definition: "A short-term loan used to finance the building of a new home or major renovation. Funds are disbursed in stages as construction progresses and the loan typically converts to a permanent mortgage upon completion.", example: "A construction-to-permanent loan funds the building of your custom home in draws, then automatically converts to a standard 30-year mortgage when construction is complete." },
    { term: "Constructive Notice", definition: "Legal notice provided by recording documents in the public records. Once recorded, everyone is considered to have notice of the document's contents, whether or not they actually read it.", example: "When a deed is recorded at the county recorder's office, it provides constructive notice to the world that the property has changed hands." },
    { term: "Consumer Financial Protection Bureau (CFPB)", definition: "A federal agency created in 2010 that regulates consumer financial products and services, including mortgages. The CFPB enforces TRID, RESPA, TILA, and other consumer protection laws.", example: "If your lender violates disclosure rules or engages in unfair practices, you can file a complaint with the CFPB at consumerfinance.gov." },
    { term: "Contingency", definition: "A condition in a purchase agreement that must be met before the sale can proceed. Common contingencies include financing, inspection, and appraisal.", example: "Your inspection contingency lets you back out or renegotiate if the home inspector finds major defects like foundation cracks or a failing roof." },
    { term: "Conventional Loan", definition: "A mortgage not insured or guaranteed by a government agency (FHA, VA, USDA). Typically requires 3-20% down and a credit score of 620+.", example: "With 20% down on a conventional loan, you avoid PMI entirely — saving $100-$300/month compared to lower down payment options." },
    { term: "Conveyance", definition: "The transfer of property ownership from one person to another through a written document such as a deed.", example: "The deed is the instrument of conveyance — it's what officially transfers the seller's ownership rights to you at closing." },
    { term: "Cooperative (Co-op)", definition: "A form of residential ownership where buyers purchase shares in a corporation that owns the building, rather than owning their individual unit directly. The shares entitle the buyer to a proprietary lease on their unit.", example: "In a co-op, you don't own your apartment — you own shares in the building corporation. The co-op board must approve new buyers, and financing can be more complex than for condos." },
    { term: "Covenant", definition: "A formal agreement containing promises and assurances between parties regarding property use or restrictions, often recorded against the property.", example: "HOA covenants may restrict what color you can paint your house, where you can park, or whether you can rent the property." },
    { term: "Credit Report", definition: "A detailed record of your borrowing and repayment history from the three major credit bureaus (Equifax, Experian, TransUnion). Lenders use it to assess risk.", example: "Your lender pulls all three credit reports and typically uses the middle score to determine your interest rate and loan eligibility." },
    { term: "Credit Score", definition: "A numerical rating (typically 300-850) that represents a borrower's creditworthiness based on payment history, amounts owed, length of credit history, new credit, and credit mix.", example: "Most mortgage lenders require a minimum credit score of 620 for conventional loans, 580 for FHA with 3.5% down, or 500 for FHA with 10% down." },
    { term: "Credit Utilization", definition: "The percentage of your available credit that you are currently using across all revolving accounts. A key factor in your credit score, ideally kept below 30%.", example: "If you have $20,000 in total credit card limits and carry $6,000 in balances, your credit utilization is 30% — lowering it to under 10% can significantly boost your score before applying for a mortgage." },
    { term: "Curative", definition: "Relating to actions taken to fix or resolve defects, issues, or irregularities in a property's title so that a clean title insurance policy can be issued.", example: "The title company identified three curative items — a missing lien release, an old deed error, and an expired judgment — all of which had to be resolved before closing." },
    { term: "Curative Work", definition: "Actions taken by a title company to resolve defects or issues found during the title search before a policy can be issued.", example: "If the title search reveals an unreleased mortgage from 2008, the title company performs curative work to obtain a release from that lender." },
    { term: "Certificate of Eligibility (COE)", definition: "A document issued by the U.S. Department of Veterans Affairs confirming a veteran's eligibility for a VA home loan, based on military service history and discharge status.", example: "Your lender can request your Certificate of Eligibility electronically through the VA portal — it confirms your entitlement amount and whether you've used VA loan benefits before." },
    { term: "Clear Title", definition: "A title to property that is free of liens, defects, encumbrances, or other legal questions as to ownership, making it eligible for transfer and title insurance.", example: "The title company won't issue a policy until all clouds are resolved and they can confirm clear title — that's why the title search and curative process are so important." },
  ],
  D: [
    { term: "Debt Consolidation", definition: "Combining multiple debts into a single payment, often through a new loan or refinancing. Homeowners sometimes use a cash-out refinance or home equity loan to consolidate higher-interest debts.", example: "Consolidating $30,000 in credit card debt (at 22% interest) into a home equity loan (at 8%) saves thousands in interest, but puts your home at risk if you can't pay." },
    { term: "Debt-to-Income Ratio (DTI)", definition: "The percentage of your gross monthly income that goes toward monthly debt payments. Lenders use front-end DTI (housing costs only, target <28%) and back-end DTI (all debts, target <43%).", example: "If you earn $7,000/month and your total debts including the new mortgage would be $2,800, your DTI is 40% — within range for most loan programs." },
    { term: "Declarations Page", definition: "The first page of a homeowner's insurance policy that summarizes key details including the policyholder's name, property address, coverage amounts, deductibles, premium, and policy period.", example: "Your lender will ask for the declarations page from your homeowner's insurance to verify coverage amounts and confirm the lender is listed as the loss payee." },
    { term: "Deductible", definition: "The amount you must pay out of pocket before your insurance coverage kicks in on a claim. Higher deductibles typically result in lower premium costs.", example: "With a $2,500 deductible, you pay the first $2,500 of a covered claim — choosing $5,000 instead could lower your annual premium by $200-$400." },
    { term: "Deed", definition: "A written legal document that conveys ownership of real property from one party (grantor) to another (grantee). Must be signed, witnessed, and recorded.", example: "At closing, the seller signs the deed transferring ownership to you. The closing agent records it with the county to make it official." },
    { term: "Deed of Trust", definition: "A document used in some states instead of a mortgage, involving three parties: the borrower (trustor), the lender (beneficiary), and a neutral third party (trustee) who holds the title.", example: "In a deed of trust state, if you default on your loan, the trustee can initiate a non-judicial foreclosure — a faster process than judicial foreclosure." },
    { term: "Deed Restriction", definition: "A limitation on how a property can be used, written into the deed itself. Deed restrictions run with the land and bind all future owners.", example: "A deed restriction might prohibit commercial use, limit building height, or require architectural approval — these restrictions remain even if the HOA dissolves." },
    { term: "Default", definition: "Failure to perform a promised task or pay an obligation when due, such as missing mortgage payments.", example: "Most lenders consider you in default after 90 days of missed payments — this triggers the acceleration clause and begins the foreclosure process." },
    { term: "Default Judgment", definition: "A court ruling in favor of the plaintiff when the defendant fails to respond to or appear in a lawsuit. In real estate, a default judgment can result in a lien on the property.", example: "If a previous owner was sued and never responded, a default judgment lien may have been placed on the property — this would appear in the title search." },
    { term: "Defect", definition: "A blemish, flaw, or imperfection in a property's title — a defective title is irregular and may not be legally valid or transferable.", example: "A forged signature on a deed from 30 years ago is a title defect that could threaten your ownership — owner's title insurance protects against this." },
    { term: "Deficiency Judgment", definition: "A court order holding a borrower personally liable for the remaining balance after a foreclosure sale if the sale proceeds do not cover the full mortgage debt.", example: "If your home sells for $250,000 at foreclosure but you owed $300,000, the lender could seek a deficiency judgment for the remaining $50,000, depending on state law." },
    { term: "Depreciation", definition: "A decrease in the value of property due to wear, age, or changing market conditions.", example: "While homes generally appreciate, factors like neighborhood decline, deferred maintenance, or environmental issues can cause depreciation." },
    { term: "Depreciation Schedule", definition: "A timeline showing how the value of an asset decreases over time. For investment properties, the IRS allows depreciation of residential rental property over 27.5 years.", example: "On a rental property purchased for $300,000 (with $50,000 allocated to land), you can deduct approximately $9,091 per year in depreciation over 27.5 years." },
    { term: "Discount Points", definition: "Upfront fees paid to the lender at closing to permanently reduce the interest rate. One point equals 1% of the loan amount.", example: "Paying 1 point ($3,500 on a $350K loan) might reduce your rate from 6.5% to 6.25% — saving $60/month or $21,600 over 30 years." },
    { term: "Down Payment", definition: "The portion of the purchase price paid in cash by the buyer at closing. The remainder is financed through a mortgage.", example: "On a $350,000 home with 10% down, your down payment is $35,000 — but remember to budget an additional 2-5% for closing costs." },
    { term: "Down Payment Assistance (DPA)", definition: "Programs offered by state and local governments, nonprofits, or employers that provide grants, forgivable loans, or low-interest loans to help homebuyers cover the down payment and closing costs.", example: "Many states offer DPA programs providing $5,000-$20,000 in grants or forgivable loans for first-time buyers who meet income limits — check your state housing finance agency." },
    { term: "Dry Closing", definition: "A closing where all documents are signed but funds are not disbursed on the same day. The transaction is completed when funds are transferred, which may happen one or more days later.", example: "In some states, a dry closing is standard — you sign everything on Monday, but the deed isn't recorded and funds aren't disbursed until the lender wires money on Tuesday." },
    { term: "Dry Funding", definition: "The disbursement of loan funds after all closing documents have been signed and recorded, rather than at the time of signing. Required in some states by law.", example: "In dry funding states like California, you sign documents one day, but the loan doesn't fund until the deed is recorded the next business day." },
    { term: "Due Diligence", definition: "The period after a purchase agreement is signed during which the buyer investigates the property through inspections, appraisal, title search, and other research.", example: "During your due diligence period, schedule inspections, review the title commitment, and verify property taxes — this is your window to back out." },
    { term: "Due-on-Sale Clause", definition: "A provision in a mortgage that requires the full loan balance to be paid when the property is sold or transferred.", example: "The due-on-sale clause prevents you from simply transferring your mortgage to a buyer — they'll need to get their own financing." },
    { term: "Duplex", definition: "A residential building containing two separate living units, each with its own entrance, kitchen, and bathroom, under a single roof.", example: "Buying a duplex and living in one unit while renting the other is a popular 'house hacking' strategy — FHA allows you to buy a duplex with just 3.5% down as an owner-occupant." },
    { term: "Dwelling Coverage", definition: "The portion of a homeowner's insurance policy that covers the cost to repair or rebuild the physical structure of your home if it is damaged or destroyed by a covered event.", example: "Your dwelling coverage should reflect the full cost to rebuild your home from the ground up — not the market value or purchase price, which includes the land." },
    { term: "Dual Agency", definition: "A situation where one real estate agent or brokerage represents both the buyer and seller in the same transaction. Legal in some states but raises conflict-of-interest concerns.", example: "In dual agency, the agent cannot fully advocate for either party — many buyer advocates recommend having your own dedicated agent who represents only your interests." },
    { term: "Disintermediation", definition: "The process of removing the middleman from a transaction. In real estate, this refers to technologies or services that connect buyers and sellers directly, reducing commissions and fees.", example: "Online platforms and iBuyers represent disintermediation in real estate — but most transactions still benefit from professional representation, especially for first-time buyers." },
    { term: "Documentary Stamp Tax", definition: "A state or local tax imposed on the transfer of real property, calculated as a fixed amount per dollar of the sale price or mortgage amount. Also called a doc stamp or deed stamp.", example: "In Florida, the documentary stamp tax on deeds is $0.70 per $100 of the sale price — on a $350,000 home, that's $2,450 paid at closing." },
  ],
  E: [
    { term: "Earnest Money", definition: "A deposit — typically 1-3% of the purchase price — given by the buyer to show good faith when making an offer. Held in escrow and credited toward closing costs.", example: "On a $350,000 home, you'll typically put down $3,500-$10,500 in earnest money when your offer is accepted — this shows the seller you're serious." },
    { term: "Easement", definition: "The legal right to use or make limited use of another person's real property for a specific purpose, such as a shared driveway, utility lines, or drainage.", example: "Your title commitment may show a utility easement allowing the power company to access their lines on a 10-foot strip along your property line." },
    { term: "Eminent Domain", definition: "The government's constitutional right to take private property for public use (roads, schools, utilities) with fair compensation to the owner.", example: "If the city needs to widen the road, eminent domain allows them to take a portion of your front yard — but they must pay you fair market value." },
    { term: "Encroachment", definition: "A structure, building, fence, or improvement that extends across the boundary line onto an adjoining property.", example: "A survey reveals your neighbor's fence is 3 feet onto your property — this encroachment should be resolved before closing to avoid future disputes." },
    { term: "Encumbrance", definition: "Any claim, right, lien, or interest in a property held by someone other than the owner that may diminish the property's value or restrict its use.", example: "Liens, easements, and restrictive covenants are all encumbrances — your title search identifies them so you know what you're buying into." },
    { term: "Endorsement", definition: "An amendment or addition to an insurance policy that modifies coverage, either expanding or restricting what the policy covers. Common in both title insurance and homeowner's insurance.", example: "If you have expensive jewelry or a home business, you may need a scheduled property endorsement added to your homeowner's policy for full coverage." },
    { term: "Equal Credit Opportunity Act (ECOA)", definition: "A federal law that prohibits lenders from discriminating against mortgage applicants based on race, color, religion, national origin, sex, marital status, age, or receipt of public assistance.", example: "Under ECOA, a lender cannot deny your mortgage application or offer less favorable terms because of your race, gender, or marital status." },
    { term: "Equity", definition: "The difference between your property's market value and the total amount you owe on it. Equity grows as you pay down your mortgage and as the property appreciates.", example: "If your home is worth $400,000 and you owe $280,000, you have $120,000 in equity — which you can access through a HELOC or cash-out refinance." },
    { term: "Equity Stripping", definition: "A predatory lending practice or asset protection strategy where the equity in a property is reduced through excessive borrowing, liens, or fees, leaving the owner with little or no ownership value.", example: "Beware of equity stripping schemes where dishonest contractors or lenders encourage you to borrow against your home equity for unnecessary work or high-fee loans." },
    { term: "Escrow", definition: "The deposit of money or documents with an impartial third party pending the completion of a transaction. Also refers to the account where your lender holds funds for property taxes and insurance.", example: "Your monthly mortgage payment includes an escrow portion for property taxes and insurance — the lender holds these funds and pays the bills on your behalf." },
    { term: "Escrow Account", definition: "An account maintained by the mortgage servicer to collect and hold funds for property taxes and homeowner's insurance, paid from monthly mortgage payments.", example: "Your escrow account analysis each year may result in a payment increase or decrease based on changes to your property tax or insurance rates." },
    { term: "Escrow Holdback", definition: "Funds held in escrow after closing to cover specific items such as incomplete repairs, seasonal work that cannot be completed at closing, or lender-required conditions.", example: "Since the exterior painting couldn't be completed in winter, the lender required a $5,000 escrow holdback to ensure the work gets done in spring." },
    { term: "Escrow Shortage", definition: "A deficit in your escrow account that occurs when the actual costs of property taxes or insurance exceed the amounts that were collected. The shortage must be repaid.", example: "If your property taxes increased and your escrow account is $800 short, your lender may spread the repayment over 12 months, increasing your monthly payment by about $67." },
    { term: "Escrow Surplus", definition: "An excess of funds in your escrow account when taxes or insurance costs were lower than anticipated. Surpluses above $50 must be refunded to the borrower.", example: "If your escrow analysis shows a $300 surplus, your lender will issue a refund check and may lower your monthly escrow payment going forward." },
    { term: "Estoppel", definition: "A legal principle that prevents a person from denying or asserting something contrary to what they previously established as truth. In condos, an estoppel letter confirms the unit's financial standing.", example: "Before buying a condo, your title company orders an estoppel letter from the HOA confirming the seller is current on dues and there are no pending special assessments." },
    { term: "Examination of Title", definition: "A review and interpretation of the title search results to determine the status of property ownership and identify any defects, liens, or encumbrances." },
    { term: "Exclusion", definition: "A specific condition, event, or type of property that an insurance policy does not cover. Knowing your exclusions is essential to understanding your actual coverage.", example: "Most homeowner's policies exclude flood damage and earthquakes — if you're in a risk area, you'll need separate policies for these perils." },
    { term: "Extended Coverage", definition: "An enhancement to a standard title insurance policy that expands protection beyond the basic policy to cover additional risks such as post-closing forgery, encroachment issues, and zoning violations.", example: "Extended coverage on your owner's title policy adds protection against survey matters, encroachments, and certain post-closing risks not covered by the standard policy." },
    { term: "Egress", definition: "The right or means to exit a property. Along with ingress (entry), egress ensures a property owner can access and leave their property.", example: "A landlocked property without a legal egress may require an easement through a neighbor's land to access a public road." },
    { term: "Environmental Assessment", definition: "An evaluation of a property for potential environmental hazards such as lead paint, asbestos, radon, underground storage tanks, or soil contamination.", example: "A Phase I environmental assessment checks for contamination on or near the property — essential before buying commercial or industrial properties, and recommended for older homes." },
    { term: "Escalation Clause", definition: "A provision in a purchase offer that automatically increases the buyer's bid by a specified amount above competing offers, up to a maximum price.", example: "An escalation clause might say you'll pay $2,000 above any competing offer up to $375,000 — it helps you stay competitive in a multiple-offer situation without overpaying." },
    { term: "Exchange (1031 Exchange)", definition: "A tax-deferred transaction under Section 1031 of the Internal Revenue Code that allows an investor to sell one investment property and purchase another of like-kind without paying capital gains taxes at the time of exchange.", example: "With a 1031 exchange, you can sell a $500,000 rental property and defer $60,000+ in capital gains taxes by reinvesting the proceeds in a replacement property within 180 days." },
    { term: "Equitable Title", definition: "The beneficial interest in a property held by a buyer under a purchase contract who has not yet received the legal title (deed). The buyer has the right to obtain full ownership upon meeting all contract terms.", example: "Once you sign the purchase agreement and the seller accepts, you hold equitable title — you have a legal interest in the property even before the deed is transferred at closing." },
    { term: "Enclosure", definition: "An area of land enclosed by a fence, wall, hedge, or other barrier. In real estate, an enclosure may or may not correspond to the actual property boundaries.", example: "A fence enclosure that doesn't match the surveyed property line can lead to boundary disputes — always compare fences to a current survey before buying." },
  ],
  F: [
    { term: "Fair Housing Act", definition: "A federal law enacted in 1968 that prohibits discrimination in the sale, rental, or financing of housing based on race, color, national origin, religion, sex, familial status, or disability.", example: "Under the Fair Housing Act, a seller cannot refuse to sell to you, and a lender cannot deny your loan, based on your race, religion, or family status." },
    { term: "Fair Market Value", definition: "The price a willing, informed buyer would pay and a willing, informed seller would accept in an open market transaction with no unusual pressure on either party." },
    { term: "Fannie Mae (FNMA)", definition: "Federal National Mortgage Association — a government-sponsored enterprise that buys and guarantees mortgages from lenders, providing liquidity to the housing market.", example: "Most conventional loans must meet Fannie Mae or Freddie Mac guidelines — including maximum loan limits, credit scores, and DTI ratios." },
    { term: "Federal Housing Administration (FHA)", definition: "A government agency within the U.S. Department of Housing and Urban Development that insures mortgage loans made by approved lenders, enabling lower down payments and more flexible qualification criteria.", example: "The FHA doesn't lend money directly — it insures loans made by private lenders, reducing their risk so they can offer mortgages to borrowers with lower credit scores and smaller down payments." },
    { term: "FHA Loan", definition: "A mortgage insured by the Federal Housing Administration, requiring as little as 3.5% down payment with a credit score of 580+. Requires mortgage insurance premium (MIP).", example: "FHA loans are popular with first-time buyers because of the low down payment, but MIP is required for the life of the loan if you put less than 10% down." },
    { term: "Fee Simple", definition: "The highest and most complete form of property ownership — unqualified ownership with full power to sell, mortgage, gift, or use the property as desired, subject only to government restrictions.", example: "When you buy a house, you typically receive fee simple ownership — the most complete form of ownership available under law." },
    { term: "FICO Score", definition: "A credit score developed by the Fair Isaac Corporation, ranging from 300 to 850, used by most mortgage lenders to evaluate a borrower's creditworthiness. Higher scores typically result in lower interest rates.", example: "A FICO score of 740+ usually qualifies you for the best mortgage rates, while a score below 620 may limit you to FHA or non-QM loan programs." },
    { term: "Fiduciary", definition: "A person or entity legally obligated to act in the best interest of another party. Real estate agents, trustees, and escrow officers owe fiduciary duties to their clients.", example: "Your buyer's agent has a fiduciary duty to you — they must prioritize your interests, disclose material facts, and maintain confidentiality." },
    { term: "Final Walkthrough", definition: "The buyer's last inspection of the property, typically within 24-48 hours of closing, to verify the home is in agreed-upon condition, repairs are completed, and no new damage has occurred.", example: "During your final walkthrough, check that all negotiated repairs were made, appliances work, and the seller hasn't removed fixtures that were supposed to stay." },
    { term: "First Mortgage", definition: "A mortgage that has first priority over all other mortgages, liens, or claims on the property. In case of default, the first mortgage is paid before any subordinate liens." },
    { term: "First-Time Buyer", definition: "As defined by most federal programs, a person who has not owned a principal residence in the past three years. This broader definition means even previous homeowners may qualify for first-time buyer programs.", example: "Even if you owned a home ten years ago, you may qualify as a first-time buyer for FHA, state DPA programs, and tax credits if you haven't owned in the past three years." },
    { term: "Fixed-Rate Mortgage", definition: "A mortgage with an interest rate that remains constant for the entire term of the loan, providing predictable monthly payments.", example: "A 30-year fixed-rate mortgage at 6.5% means your principal and interest payment never changes — only taxes and insurance may fluctuate." },
    { term: "Fixture", definition: "An item of personal property that has been permanently attached to or incorporated into the real property and is therefore considered part of the real estate.", example: "Built-in bookshelves, ceiling fans, and light fixtures are typically considered fixtures that convey with the property — a freestanding refrigerator usually is not." },
    { term: "Flood Certification", definition: "A determination of whether a property is located in a FEMA-designated flood zone, which would require flood insurance.", example: "If your flood certification shows you're in Zone AE, your lender will require flood insurance — typically $700-$2,000+ per year on top of your homeowner's policy." },
    { term: "Floor Plan", definition: "A scaled drawing showing the layout of rooms, dimensions, and the relationship between spaces within a building, viewed from above.", example: "Review the floor plan carefully in new construction — an open floor plan may look great on paper, but consider traffic flow and furniture placement." },
    { term: "Flood Zone", definition: "A geographic area designated by FEMA on Flood Insurance Rate Maps (FIRMs) based on the level of flood risk. Zone A and Zone V are high-risk areas where flood insurance is mandatory for federally backed mortgages.", example: "FEMA flood zone designations can change over time — even if your property isn't in a high-risk zone today, check updated maps periodically and consider flood insurance regardless." },
    { term: "Forbearance", definition: "A temporary agreement between a lender and borrower to reduce or suspend mortgage payments for a specified period due to financial hardship, without triggering foreclosure.", example: "During COVID-19, millions of homeowners used forbearance to pause their mortgage payments for up to 18 months — the missed payments were added to the end of the loan." },
    { term: "Foreclosure", definition: "A legal proceeding in which a lender takes possession of a property after the borrower defaults on mortgage payments, selling it to recover the outstanding debt." },
    { term: "Freddie Mac (FHLMC)", definition: "Federal Home Loan Mortgage Corporation — a government-sponsored enterprise similar to Fannie Mae that buys and guarantees mortgages to support the housing market." },
    { term: "Funding", definition: "The disbursement of mortgage loan proceeds from the lender to the closing agent or escrow company, enabling the transaction to be completed and the deed to be recorded.", example: "Once the lender wires the funds to the title company, the transaction is 'funded' and the closing agent can record the deed and disburse proceeds to the seller." },
    { term: "Funding Fee", definition: "An upfront fee charged on VA and USDA loans in lieu of mortgage insurance. The VA funding fee is 2.15% for first-time use and can be financed into the loan.", example: "On a $300,000 VA loan, the funding fee is $6,450 — but it can be rolled into the loan amount, and disabled veterans are exempt." },
    { term: "For Sale By Owner (FSBO)", definition: "A property sale handled directly by the owner without a listing agent, intended to save on real estate commissions.", example: "Buying a FSBO home can mean a lower price since the seller saves on commission, but you'll want your own buyer's agent or attorney to protect your interests." },
    { term: "Floodplain", definition: "A flat area of land adjacent to a river, stream, or other body of water that is subject to periodic flooding. Properties in a floodplain typically require flood insurance and may face building restrictions.", example: "If your property is in a 100-year floodplain, your lender will require flood insurance — and local regulations may restrict additions or new construction in the floodplain area." },
  ],
  G: [
    { term: "Gap Coverage (Insurance)", definition: "Additional homeowner's insurance that covers the difference between the amount owed on a vehicle or property and its actual cash value at the time of a total loss.", example: "Gap coverage can also refer to the period between the title search date and recording date — title companies often insure this 'gap' to protect against liens filed in between." },
    { term: "Gap Search", definition: "A title search conducted between the date of the original title commitment and the recording date of the deed, checking for any new liens, judgments, or encumbrances filed during that gap period.", example: "The title company runs a gap search right before recording the deed to make sure no new liens were filed against the property since the original title search." },
    { term: "General Warranty Deed", definition: "The strongest form of deed warranty, guaranteeing clear title against all claims — past and present — and providing the buyer with the most protection.", example: "A general warranty deed means the seller guarantees the title is free of ALL defects, even those from before they owned the property." },
    { term: "Gift Letter", definition: "A written statement from a family member or other approved donor confirming that funds given to a homebuyer for the down payment or closing costs are a gift and not a loan that must be repaid.", example: "If your parents give you $20,000 for a down payment, the lender will require a signed gift letter stating the money is a gift with no expectation of repayment." },
    { term: "Good Faith Estimate (GFE)", definition: "A former disclosure document replaced by the Loan Estimate in 2015 under the TRID rule. It provided an estimate of settlement charges.", example: "If someone mentions a 'Good Faith Estimate,' they're referring to the old form — the modern equivalent is the Loan Estimate required under TRID." },
    { term: "Good Funds", definition: "Funds that are immediately available and guaranteed, such as wire transfers, cashier's checks, or certified checks. Required for closing transactions in most states.", example: "Most title companies require good funds for closing — a personal check for $50,000 won't work because it takes days to clear. Bring a cashier's check or wire the funds." },
    { term: "Government Recording Fee", definition: "Fees charged by the county recorder's office to officially record real estate documents such as the deed, mortgage, and any other instruments in the public records.", example: "Government recording fees typically range from $50 to $250 depending on the county and the number of pages being recorded." },
    { term: "Government-Sponsored Enterprise (GSE)", definition: "A financial services corporation created by Congress to enhance the flow of credit to specific economic sectors. Fannie Mae and Freddie Mac are the primary housing GSEs." },
    { term: "Grantee", definition: "The person or entity receiving ownership of property through a deed — the buyer in a real estate transaction." },
    { term: "Grantor", definition: "The person or entity transferring ownership of property through a deed — the seller in a real estate transaction." },
    { term: "Gross Monthly Income", definition: "Your total monthly income before taxes and deductions. Lenders use this figure to calculate your debt-to-income ratio.", example: "If your annual salary is $84,000, your gross monthly income is $7,000 — and your maximum recommended housing payment (28% rule) would be $1,960." },
    { term: "Guarantee Fee", definition: "An upfront and annual fee charged on USDA loans (similar to FHA's MIP or VA's funding fee) that funds the USDA loan guarantee program.", example: "The USDA guarantee fee includes a 1% upfront fee (which can be financed) and a 0.35% annual fee — both lower than FHA's mortgage insurance premiums." },
    { term: "Guardian", definition: "A person appointed by a court to manage the legal and financial affairs of someone who cannot manage their own, such as a minor or incapacitated adult. A guardian may need court approval to sell property.", example: "If the property is owned by a minor, a court-appointed guardian must obtain court approval to sign the deed, which can add weeks to the closing timeline." },
    { term: "Gift Funds", definition: "Money received from a family member, domestic partner, or other approved donor to be used toward a home purchase down payment or closing costs. Lenders require documentation that the funds are a true gift, not a loan.", example: "FHA, VA, and conventional loans all allow gift funds for the down payment, but each program has specific rules about who can give and how the gift must be documented." },
    { term: "Grace Period", definition: "A set number of days after the mortgage payment due date during which the payment can be made without incurring a late fee. Most mortgages have a 15-day grace period.", example: "If your mortgage payment is due on the 1st and your grace period is 15 days, you can pay anytime through the 15th without a late fee — but interest continues to accrue." },
    { term: "Ground Rent", definition: "A periodic payment made by a property owner to the owner of the land on which the property sits, common in leasehold arrangements in states like Maryland.", example: "In parts of Baltimore, homeowners pay ground rent of $50-$150 per year to the landowner — the ground rent can usually be redeemed (purchased outright) for a lump sum." },
    { term: "Gross Rent Multiplier (GRM)", definition: "A simple ratio used to evaluate rental property investments, calculated by dividing the property's purchase price by its gross annual rental income.", example: "A property selling for $300,000 with annual rental income of $30,000 has a GRM of 10 — lower GRMs generally indicate better investment value, but don't account for expenses." },
  ],
  H: [
    { term: "Habendum Clause", definition: "The clause in a deed that defines the extent of ownership being granted, beginning with the words 'to have and to hold.' It specifies whether the grantee receives full ownership or a limited interest.", example: "The habendum clause in your deed will typically read 'to have and to hold in fee simple forever,' confirming you receive full, unrestricted ownership of the property." },
    { term: "Hazard Insurance", definition: "Insurance protecting the property against damage from fire, windstorms, hail, vandalism, and other covered perils. Often used interchangeably with homeowner's insurance.", example: "Your lender requires hazard insurance with coverage at least equal to the loan amount — you'll need proof of the policy before closing." },
    { term: "Heir", definition: "A person who is legally entitled to inherit property from a deceased person, either through a will or by state intestacy laws if no will exists.", example: "Title searches check for unknown heirs who might have a claim to the property — title insurance protects you if an heir comes forward after closing." },
    { term: "HELOC", definition: "Home Equity Line of Credit — a revolving credit line secured by your home's equity, allowing you to borrow as needed up to a set limit during a draw period.", example: "After building equity, you might open a HELOC at 8% to fund home improvements — better than a credit card at 20%+." },
    { term: "HOA (Homeowners Association)", definition: "An organization in a subdivision or condo complex that makes and enforces rules, maintains common areas, and collects dues from homeowners.", example: "Monthly HOA fees of $200-$500 cover maintenance of common areas, pools, and landscaping — but they add to your total housing cost, so include them in your budget." },
    { term: "Hold Harmless", definition: "A clause in a contract where one party agrees to protect the other from liability or legal claims arising from the transaction or activity.", example: "The seller may sign a hold harmless agreement promising to protect the buyer from claims related to work done on the property before the sale." },
    { term: "Home Equity", definition: "The portion of your property's value that you actually own — the difference between the home's current market value and any outstanding mortgage balances." },
    { term: "Home Equity Loan", definition: "A fixed-rate loan that allows homeowners to borrow a lump sum against the equity in their home, repaid in fixed monthly installments over a set term.", example: "A home equity loan gives you a lump sum at a fixed rate — unlike a HELOC which is variable — making it better for one-time expenses like a kitchen remodel." },
    { term: "Home Inspection", definition: "A professional examination of a property's physical condition, including structure, roof, plumbing, electrical, HVAC, foundation, and more. Typically costs $300-$500.", example: "A home inspection can reveal $40,000+ in hidden problems — attend in person and ask the inspector to explain which findings are critical vs. cosmetic." },
    { term: "Home Mortgage Disclosure Act (HMDA)", definition: "A federal law requiring financial institutions to report data about their mortgage lending activity, including the race, ethnicity, income, and geographic location of borrowers, to ensure fair lending practices.", example: "HMDA data is publicly available and helps regulators identify potential lending discrimination patterns in specific communities." },
    { term: "Home Price Index (HPI)", definition: "A statistical measure that tracks changes in residential property prices over time, published by organizations such as the Federal Housing Finance Agency (FHFA) and S&P/Case-Shiller.", example: "The FHFA Home Price Index showed a 5% annual increase nationally, but local markets can vary significantly — some areas saw 10% gains while others were flat." },
    { term: "Homeowner's Insurance", definition: "A comprehensive insurance policy covering the home's structure, personal property, liability, and additional living expenses. Required by mortgage lenders.", example: "A standard HO-3 policy covers your home against most perils except floods and earthquakes — shop 3-4 carriers to find the best rate." },
    { term: "Homestead Exemption", definition: "A legal provision that reduces the taxable value of a primary residence, lowering the property tax bill. Available in many states with varying amounts and eligibility requirements.", example: "In Texas, the homestead exemption can reduce your property's taxable value by at least $100,000 for school district taxes — file with your county appraisal district after closing." },
    { term: "Housing Ratio", definition: "The front-end debt-to-income ratio that compares monthly housing costs (PITI plus HOA) to gross monthly income. Most lenders prefer this ratio to be at or below 28%.", example: "If your gross monthly income is $8,000 and your total housing payment is $2,200, your housing ratio is 27.5% — within the recommended 28% guideline." },
    { term: "HUD", definition: "The U.S. Department of Housing and Urban Development — a federal agency that oversees housing programs, enforces fair housing laws, and regulates FHA lending.", example: "HUD publishes annual income limits that determine eligibility for FHA loans and various down payment assistance programs in your area." },
    { term: "HUD-1 Settlement Statement", definition: "A former closing document replaced by the Closing Disclosure in 2015. It itemized all charges to the buyer and seller in a real estate transaction." },
    { term: "Home Warranty", definition: "A service contract that covers the repair or replacement of major home systems and appliances (HVAC, plumbing, electrical, water heater, kitchen appliances) that fail due to normal wear and tear during the coverage period.", example: "A home warranty costs $400-$700/year and covers repairs to systems and appliances — sellers often provide one as a buyer incentive, especially for older homes." },
    { term: "Hurricane Insurance", definition: "Specialized insurance coverage for wind and storm damage caused by hurricanes, often required as a separate policy or endorsement in coastal areas where standard homeowner's policies exclude or limit wind coverage.", example: "In Florida and other Gulf Coast states, hurricane/windstorm insurance is often a separate policy from your homeowner's insurance and can cost $2,000-$10,000+ depending on proximity to the coast." },
  ],
  I: [
    { term: "Impound Account", definition: "Another term for an escrow account — funds collected monthly by the lender for property taxes and insurance.", example: "In California, lenders typically call the escrow account an 'impound account' — same thing, different name." },
    { term: "Imputed Interest", definition: "The minimum interest rate the IRS assumes on certain loans, even if the actual rate charged is lower. Applies to seller-financed transactions and below-market loans.", example: "If you buy a home from a family member at 0% interest, the IRS may impute interest at the applicable federal rate and tax you as if you were earning that interest." },
    { term: "Indemnity", definition: "An agreement in which one party compensates another for a loss or damage. In title insurance, the policy is an indemnity contract that reimburses the insured for covered losses.", example: "Title insurance is an indemnity product — if a covered title defect causes you financial loss, the insurer pays to make you whole, up to the policy amount." },
    { term: "Index Rate", definition: "A benchmark interest rate used to calculate the adjustable rate on an ARM. Common indexes include SOFR (Secured Overnight Financing Rate) and the 1-Year Treasury.", example: "Your ARM rate equals the index rate plus the margin — if SOFR is 4.5% and your margin is 2%, your adjusted rate would be 6.5%." },
    { term: "Ingress", definition: "The right or permission to enter a property — the means or place of entry such as a right-of-way or easement providing access." },
    { term: "Insured Closing Letter", definition: "A letter issued by a title insurance underwriter to the lender guaranteeing that the title agent will handle the closing in accordance with the lender's written instructions.", example: "The insured closing letter protects the lender from losses caused by the closing agent's fraud, dishonesty, or failure to follow closing instructions." },
    { term: "Interest Rate", definition: "The percentage charged by a lender for borrowing money, expressed as an annual percentage. Different from APR, which includes fees.", example: "Your interest rate determines your base monthly payment, but always compare APRs between lenders — the APR includes fees in the true cost." },
    { term: "Interest Rate Lock", definition: "A lender's commitment to hold a specific interest rate for a set period (typically 30-60 days), protecting you from rate increases before closing.", example: "Lock your rate when you're comfortable with it — if rates rise 0.5% before you close, a locked rate saves you $100+/month on a $350K loan." },
    { term: "Interest-Only Mortgage", definition: "A mortgage where the borrower pays only interest for a set initial period (typically 5-10 years), after which payments increase to include principal amortization for the remaining term.", example: "An interest-only mortgage on a $400,000 loan at 6.5% means payments of $2,167/month for the first 10 years, but they jump to $2,932 once principal repayment begins." },
    { term: "Investment Property", definition: "Real estate purchased with the intention of earning a return through rental income, appreciation, or both, rather than as a primary residence.", example: "Investment property mortgages typically require 15-25% down, carry interest rates 0.5-0.75% higher than primary residence loans, and have stricter qualification requirements." },
    { term: "Intestate", definition: "Dying without a valid will. When a property owner dies intestate, state law determines how the property is distributed among heirs.", example: "If a property owner dies intestate, the title may need to pass through probate before it can be sold, which can add months to the closing timeline." },
    { term: "IRRRL (Interest Rate Reduction Refinance Loan)", definition: "A VA streamline refinance program that allows eligible veterans to refinance an existing VA loan to a lower interest rate with minimal documentation and no appraisal requirement.", example: "The VA IRRRL lets you refinance your existing VA loan with reduced paperwork, no appraisal, and no out-of-pocket costs if the fees are rolled into the loan." },
    { term: "Improvement", definition: "Any addition to or modification of real property that increases its value, such as buildings, fences, driveways, landscaping, or utility installations.", example: "Improvements like a new kitchen, added bathroom, or finished basement increase your home's value — but always check if a building permit is required before starting work." },
    { term: "Indemnification", definition: "A contractual obligation by one party to compensate another for losses or damages arising from a specified event or action, commonly found in real estate purchase agreements and closing documents.", example: "The purchase agreement may include an indemnification clause requiring the seller to compensate you for any losses caused by undisclosed defects discovered after closing." },
    { term: "Inspection Contingency", definition: "A clause in a purchase agreement that gives the buyer the right to have the property professionally inspected within a specified time frame and to negotiate repairs, credits, or cancellation based on the findings.", example: "A standard inspection contingency gives you 7-14 days to complete inspections and request repairs — in competitive markets, some buyers waive this, but it's a significant risk." },
    { term: "Interim Financing", definition: "A short-term loan used to bridge the gap between the purchase of a new property and the sale of an existing one, or to fund construction until permanent financing is obtained.", example: "Interim financing through a bridge loan allowed the buyers to close on their new home without waiting for their existing home to sell, though the interest rate was 2% higher than a standard mortgage." },
  ],
  J: [
    { term: "Joint Tenancy", definition: "A form of co-ownership where two or more persons hold equal, undivided interests with the right of survivorship — meaning a deceased owner's share automatically passes to the surviving owners.", example: "Married couples often take title as joint tenants — if one spouse dies, the surviving spouse automatically receives full ownership without probate." },
    { term: "Joint Venture", definition: "A business arrangement in which two or more parties agree to pool resources and share profits, losses, and control of a specific real estate project or investment.", example: "A developer and an investor might form a joint venture to build a subdivision — the developer contributes expertise and the investor provides capital." },
    { term: "Judgment", definition: "A court order requiring one party to pay money or take action. A judgment against a property owner becomes a lien against their real estate.", example: "If the previous owner lost a lawsuit and a $50,000 judgment was filed, it attaches to the property as a lien that must be resolved before closing." },
    { term: "Judgment Lien", definition: "A lien placed on a property as the result of a court judgment. Must be paid or resolved before the property can be sold with clear title.", example: "Your title search might reveal a judgment lien from an unpaid credit card lawsuit — the seller must pay this off before transferring clear title to you." },
    { term: "Jumbo Loan", definition: "A mortgage that exceeds the conforming loan limits set by Fannie Mae and Freddie Mac ($806,500 in most areas for 2025, higher in high-cost areas).", example: "Buying a $900,000 home requires a jumbo loan, which typically needs 10-20% down, a 700+ credit score, and may have a slightly higher interest rate." },
    { term: "Jurisdiction", definition: "The geographic area or subject matter over which a court or government body has legal authority. Property transactions are governed by the jurisdiction where the property is located.", example: "Closing practices vary by jurisdiction — some states require attorneys at closing while others use title companies or escrow agents." },
    { term: "Joint Liability", definition: "A legal obligation shared equally by two or more parties, where each party is individually responsible for the entire debt or obligation. Common with co-borrowers on a mortgage.", example: "With joint liability on a mortgage, both co-borrowers are responsible for the full loan amount — if one stops paying, the lender can pursue the other for the entire balance." },
    { term: "Junior Lien", definition: "A lien that is subordinate in priority to a previously recorded lien. In the event of foreclosure, senior liens are paid first, and junior liens receive whatever remains.", example: "A HELOC recorded after your first mortgage is a junior lien — if the property goes to foreclosure, the first mortgage gets paid in full before the HELOC receives anything." },
  ],
  K: [
    { term: "Kick-Out Clause", definition: "A provision in a purchase agreement that allows the seller to continue marketing the property and accept a better offer, giving the original buyer a set time to remove their contingency or be replaced.", example: "With a kick-out clause, if another buyer makes an offer, you have 48-72 hours to remove your home-sale contingency or lose the deal." },
    { term: "Knowledge-Based Authentication (KBA)", definition: "An identity verification method used in Remote Online Notarization (RON) where the signer answers questions about their personal history that only they would know.", example: "During a RON closing, you'll answer questions like 'Which of these addresses have you lived at?' to verify your identity before signing." },
    { term: "Key Money", definition: "A payment made by a tenant or buyer to a landlord, property owner, or current tenant to secure the right to lease or purchase a property. Common in competitive urban rental markets.", example: "In some tight housing markets, tenants pay key money — sometimes thousands of dollars — to secure a desirable rental unit, though the practice is illegal in many jurisdictions." },
    { term: "Knob-and-Tube Wiring", definition: "An early method of electrical wiring used in homes built before the 1940s, featuring individual wires run through ceramic knobs and tubes. Considered a fire hazard and often flagged by inspectors and insurers.", example: "If the home inspection reveals knob-and-tube wiring, many insurance companies will refuse coverage until it's replaced — budget $8,000-$15,000 for a full rewiring." },
  ],
  L: [
    { term: "Land Patent", definition: "The original document by which the government grants ownership of public land to a private individual. The very first title transfer in a property's chain of title.", example: "A land patent from the 1800s may be the starting point of a chain of title, representing the federal government's original grant of the land to a private owner." },
    { term: "Lease", definition: "An agreement granting use and occupancy of property for a specified period in exchange for rent payments." },
    { term: "Leasehold", definition: "A form of property interest where the buyer holds a long-term lease on the land rather than owning it outright. Common in Hawaii, parts of New York, and on tribal lands.", example: "With a leasehold property, you own the building but lease the land beneath it — when the lease expires, ownership of the building may revert to the landowner." },
    { term: "Lender Credits", definition: "Funds provided by the lender to the borrower at closing to offset closing costs, typically in exchange for accepting a higher interest rate on the loan.", example: "Your lender offers $4,000 in credits if you accept a rate of 6.75% instead of 6.5% — this reduces your upfront closing costs but increases your monthly payment by about $50." },
    { term: "Lender's Title Insurance", definition: "A title insurance policy protecting the mortgage lender's financial interest in the property. Required by virtually all lenders. Paid by the buyer.", example: "The lender's policy protects the bank, not you — that's why you also need an owner's policy to protect your own investment." },
    { term: "Liability Coverage", definition: "The portion of a homeowner's insurance policy that protects you financially if someone is injured on your property or if you accidentally damage someone else's property.", example: "If a guest trips on your front steps and sues you, liability coverage (typically $100,000-$500,000) pays for their medical bills and your legal defense." },
    { term: "Lien", definition: "A legal claim against real property used as security for the payment of a debt. Common types include mortgage liens, tax liens, mechanic's liens, and judgment liens.", example: "If a contractor who worked on the home wasn't paid, they can file a mechanic's lien — the title search is designed to catch this before you close." },
    { term: "Lis Pendens", definition: "A legal notice filed in public records warning that a lawsuit is pending that may affect the title to a specific property.", example: "A lis pendens on a property means there's active litigation — most buyers won't close until the case is resolved." },
    { term: "Litigation", definition: "The process of resolving a dispute through the court system, including lawsuits related to property ownership, contract disputes, or boundary disagreements.", example: "Active litigation involving the property can delay or prevent closing — the title company will require the lawsuit to be resolved or dismissed before issuing a policy." },
    { term: "Loan Estimate (LE)", definition: "A three-page standardized document that lenders must provide within three business days of a mortgage application, detailing estimated interest rate, monthly payments, and closing costs.", example: "Get Loan Estimates from at least 3 lenders and compare APRs, origination charges, and total closing costs — the standardized format makes comparison easy." },
    { term: "Loan Origination Fee", definition: "A fee charged by the lender for processing a new mortgage application. Usually expressed as a percentage of the loan amount (0.5-1%).", example: "An origination fee of 1% on a $350,000 loan is $3,500 — this is negotiable, so ask the lender if they can reduce or waive it." },
    { term: "Loan Policy", definition: "A title insurance policy issued to a mortgage lender protecting their interest against title defects, liens, and competing claims.", example: "The loan policy protects the lender's declining balance — as you pay down the mortgage, the coverage decreases. That's why you need a separate owner's policy." },
    { term: "Loan-to-Value Ratio (LTV)", definition: "The ratio of the mortgage amount to the appraised property value, expressed as a percentage. Higher LTV means more risk for the lender and usually requires mortgage insurance.", example: "With $35,000 down on a $350,000 home, your LTV is 90% — above 80%, so you'll need PMI on a conventional loan." },
    { term: "Lock Period", definition: "The time frame during which a lender guarantees a specific interest rate. Common lock periods are 30, 45, and 60 days.", example: "A 30-day lock is usually free; a 60-day lock might cost 0.125% extra — make sure your closing date falls within the lock period." },
    { term: "Loss Payee", definition: "The party designated on an insurance policy to receive payment in the event of a covered loss. Your mortgage lender is listed as the loss payee on your homeowner's insurance.", example: "Your lender is listed as loss payee on your homeowner's policy — if your home is destroyed, the insurance check is made payable to both you and the lender." },
    { term: "Lot", definition: "A specific parcel of land with defined boundaries, identified by a lot number on a recorded plat map or subdivision plan.", example: "Your property is legally described as 'Lot 14, Block 3 of Willow Creek Subdivision' — this lot description ties to the recorded plat map at the county recorder's office." },
    { term: "Loan Servicer", definition: "The company that manages your mortgage after closing, including collecting monthly payments, managing the escrow account, and handling customer service. May be different from the original lender.", example: "Your loan may be sold to a different servicer after closing — don't be surprised if you start getting payment instructions from a company you've never heard of." },
    { term: "Legal Description", definition: "A formal description of a property that precisely identifies it for legal purposes, using methods such as lot and block, metes and bounds, or the government survey system.", example: "Your deed's legal description might read 'Lot 7, Block 2, of Sunrise Estates, as recorded in Plat Book 42, Page 16' — this is more precise than a street address." },
    { term: "Land Use", definition: "The way in which a parcel of land is utilized, such as residential, commercial, agricultural, or industrial. Land use is regulated by local zoning ordinances and comprehensive plans.", example: "Before purchasing property for a business, verify the current land use designation allows commercial activity — changing land use requires a rezoning application and public hearings." },
    { term: "Latent Defect", definition: "A hidden flaw or deficiency in a property that is not visible or apparent during a reasonable inspection and that the seller may be legally obligated to disclose if known.", example: "A cracked foundation hidden behind finished walls is a latent defect — if the seller knew about it and didn't disclose it, they may be liable for repair costs even after closing." },
  ],
  M: [
    { term: "Margin", definition: "The fixed percentage added to the index rate to determine the interest rate on an adjustable-rate mortgage at each adjustment. The margin remains constant for the life of the loan.", example: "If your ARM has a margin of 2.75% and the index rate is 4%, your adjusted rate would be 6.75% — the margin never changes, but the index does." },
    { term: "Marketable Title", definition: "A title free of material defects, liens, and encumbrances — one that a reasonable buyer would accept and a court would require a buyer to accept." },
    { term: "Market Value", definition: "The most probable price a property would bring in an open, competitive market where both buyer and seller are acting prudently and without unusual pressure." },
    { term: "Master Policy", definition: "A single title insurance policy issued to cover multiple properties or transactions, typically used by large lenders or developers to streamline coverage across a portfolio.", example: "A condo developer may obtain a master title insurance policy covering all units in the building, with individual policies issued to each buyer at closing." },
    { term: "Mechanic's Lien", definition: "A lien filed by a contractor, subcontractor, or material supplier who performed work on a property and was not paid. Takes priority from the date work began.", example: "If the seller hired a roofer who wasn't fully paid, the roofer can file a mechanic's lien — your title insurance protects you if this isn't caught before closing." },
    { term: "Mediation", definition: "A voluntary dispute resolution process where a neutral third party (mediator) helps the parties negotiate a settlement, without making a binding decision.", example: "Many real estate contracts require mediation before arbitration or litigation — it's often faster and cheaper, and both parties have more control over the outcome." },
    { term: "Metes and Bounds", definition: "A legal method of describing property boundaries using compass directions, distances, and physical landmarks, starting from a defined point of beginning." },
    { term: "MIP (Mortgage Insurance Premium)", definition: "The insurance premium on FHA loans, consisting of an upfront premium (1.75% of the loan, financed into the balance) and an annual premium (0.55% of the loan, paid monthly).", example: "On a $300,000 FHA loan, upfront MIP is $5,250 (added to loan) and annual MIP is $1,650/year ($137.50/month) — for the life of the loan if you put less than 10% down." },
    { term: "Modification (Loan Modification)", definition: "A permanent change to one or more terms of an existing mortgage — such as the interest rate, loan term, or principal balance — to make payments more affordable and help the borrower avoid foreclosure.", example: "If you're struggling with payments, a loan modification might reduce your rate from 7% to 5% or extend your term from 25 to 40 years, lowering your monthly payment." },
    { term: "Mortgage", definition: "A legal instrument that pledges property as security for repayment of a loan. If the borrower defaults, the lender can foreclose to recover the debt." },
    { term: "Mortgage Broker", definition: "A licensed professional who shops multiple lenders on behalf of the borrower to find the best loan terms, earning a commission from the lender or borrower." },
    { term: "Mortgage Commitment", definition: "A formal, written promise from a lender to provide a mortgage loan under specific terms and conditions, issued after the loan has been fully underwritten and approved.", example: "A mortgage commitment letter is stronger than pre-approval — it means the lender has completed underwriting and is committed to funding your loan, subject to final conditions like the title search." },
    { term: "Mortgage Insurance", definition: "Insurance that protects the lender if the borrower defaults. Required on conventional loans with less than 20% down (PMI), FHA loans (MIP), and USDA loans (guarantee fee)." },
    { term: "Multi-Family Property", definition: "A residential building designed to house more than one family in separate units, such as duplexes, triplexes, fourplexes, and apartment buildings.", example: "You can buy a multi-family property (up to 4 units) with an FHA loan and just 3.5% down, as long as you live in one of the units as your primary residence." },
    { term: "Mineral Rights", definition: "The ownership rights to natural resources (oil, gas, coal, metals) beneath the surface of a property. Mineral rights can be severed from surface rights and sold separately.", example: "In many Western states, mineral rights may have been separated from the land decades ago — the title search should reveal if someone else owns the rights to resources under your property." },
    { term: "Multiple Listing Service (MLS)", definition: "A database maintained by real estate brokers where listed properties are shared among agents, providing comprehensive information about homes for sale in a given area.", example: "Your agent lists your home on the MLS, which feeds to sites like Zillow and Realtor.com, maximizing exposure to potential buyers." },
    { term: "Mortgage Rate", definition: "The interest rate charged on a mortgage loan, which determines the cost of borrowing and directly affects the monthly payment amount.", example: "Even a small difference in mortgage rates matters — on a $350,000 loan, the difference between 6.0% and 6.5% is about $115/month or $41,400 over 30 years." },
    { term: "Move-In Costs", definition: "The total upfront expenses a buyer faces when purchasing a home, including down payment, closing costs, prepaid items, moving expenses, and any immediate repairs or furnishing.", example: "Beyond the down payment and closing costs, budget $2,000-$5,000 for moving expenses, utility deposits, new locks, and immediate household needs." },
    { term: "Mortgage Note", definition: "The legal document that serves as evidence of a debt and the borrower's promise to repay the mortgage loan according to specified terms including interest rate, payment schedule, and maturity date.", example: "The mortgage note is your personal promise to repay — even if you sell or lose the property, you remain personally liable for the debt unless the note is satisfied or released." },
    { term: "Moratorium", definition: "A temporary suspension or delay of an activity or obligation, such as a government-imposed halt on foreclosures, evictions, or new construction in a specific area.", example: "During the 2020 pandemic, the federal government imposed a foreclosure moratorium protecting homeowners with federally backed mortgages from losing their homes." },
  ],
  N: [
    { term: "Named Peril", definition: "A type of insurance policy that only covers losses caused by specific perils that are explicitly listed in the policy, such as fire, theft, or windstorm.", example: "A named peril policy is cheaper than an open peril policy because it covers fewer risks — make sure the named perils include the hazards most common in your area." },
    { term: "National Flood Insurance Program (NFIP)", definition: "A federal program administered by FEMA that provides flood insurance to property owners in participating communities, since standard homeowner's policies exclude flood damage.", example: "If your property is in a FEMA flood zone, your lender will require flood insurance through the NFIP or a private flood insurer before closing." },
    { term: "Negative Amortization", definition: "A situation where monthly payments are so low that they don't cover the interest due, causing the unpaid interest to be added to the loan balance — the amount owed actually increases over time." },
    { term: "Net Worth", definition: "The total value of all your assets (savings, investments, property, retirement accounts) minus all your liabilities (debts, loans, obligations).", example: "Your net worth improves each month as you pay down your mortgage and your home appreciates — a $350,000 home with $280,000 owed contributes $70,000 to your net worth." },
    { term: "Non-QM Loan (Non-Qualified Mortgage)", definition: "A mortgage that does not meet the Consumer Financial Protection Bureau's qualified mortgage standards but is still a legitimate loan product for borrowers who don't fit traditional lending criteria.", example: "Self-employed borrowers, investors, and those with non-traditional income often use non-QM loans like bank statement loans or asset depletion loans to qualify." },
    { term: "Notarization", definition: "The official act of a notary public witnessing the signing of a document, verifying the signer's identity, and applying their seal as evidence of authenticity." },
    { term: "Notary Public", definition: "A state-commissioned official authorized to administer oaths, witness signatures, and certify documents. Required for real estate deeds and mortgage documents." },
    { term: "Note (Promissory Note)", definition: "A written, signed document containing a promise to pay a specified sum of money at a stated time. The note is your personal promise to repay the mortgage.", example: "The promissory note details your loan amount, interest rate, payment schedule, and what happens if you default — it's the core of your mortgage obligation." },
    { term: "Notice of Default (NOD)", definition: "A formal written notice from a lender to a borrower stating that the borrower is in default on their mortgage and that foreclosure proceedings may begin if the default is not cured.", example: "A notice of default is typically filed after 90+ days of missed payments — once filed, you may have 30-90 days (depending on state law) to bring the loan current." },
    { term: "Non-Conforming Loan", definition: "A mortgage that does not meet the guidelines set by Fannie Mae or Freddie Mac, either because the loan amount exceeds conforming limits (jumbo loan) or because the borrower or property doesn't meet standard criteria.", example: "A non-conforming loan may be necessary for a self-employed borrower with non-standard income documentation, a unique property type, or a loan amount above the conforming limit." },
    { term: "Notice to Proceed", definition: "A formal written authorization from a lender, buyer, or project owner directing that work or a specific phase of the transaction may begin, commonly used in new construction and renovation loans.", example: "The lender issued a notice to proceed after the construction loan closed, authorizing the builder to begin site preparation and foundation work." },
    { term: "Net Listing", definition: "A listing agreement in which the seller sets a minimum acceptable net price and the broker keeps any amount above that as commission. Illegal or discouraged in most states due to conflict-of-interest concerns.", example: "In a net listing, if the seller wants $300,000 net and the broker sells for $340,000, the broker keeps $40,000 — this creates an incentive for the broker to act against the seller's best interest." },
    { term: "Negative Equity", definition: "A situation in which the outstanding balance on a mortgage exceeds the current market value of the property, meaning the owner owes more than the home is worth.", example: "If you owe $320,000 on a home now worth $280,000, you have $40,000 in negative equity — also called being 'underwater' — making it difficult to sell or refinance." },
    { term: "Net Operating Income (NOI)", definition: "The total income generated by a rental or investment property minus all operating expenses (taxes, insurance, maintenance, management), but before mortgage payments and income taxes.", example: "A rental property generating $36,000 in annual rent with $12,000 in operating expenses has a net operating income of $24,000 — this figure is used to calculate the cap rate." },
  ],
  O: [
    { term: "Open Peril", definition: "A type of insurance policy (also called 'all-risk') that covers all causes of loss except those specifically excluded in the policy. Provides broader protection than named peril coverage.", example: "An open peril (all-risk) policy covers any damage not explicitly excluded — so if a meteorite hits your roof, you're covered, even though 'meteorite' isn't listed." },
    { term: "Origination", definition: "The process of creating a new mortgage loan, from application through underwriting, approval, and funding." },
    { term: "Origination Points", definition: "Fees paid to the lender at closing for processing and originating the mortgage loan, expressed as a percentage of the loan amount. One origination point equals 1% of the loan.", example: "Some lenders charge 1 origination point ($3,000 on a $300,000 loan) while others charge none — always factor origination points into your total cost comparison." },
    { term: "Owner's Policy", definition: "A title insurance policy protecting the homeowner's property rights and investment for the life of ownership and their heirs' interest. Purchased for a one-time fee at closing.", example: "The owner's policy costs about 0.5-1% of the purchase price — a one-time fee that protects your $350,000+ investment for as long as you own the home." },
    { term: "Owner-Occupied", definition: "A property that is used as the owner's primary residence, as opposed to a second home or investment property. Owner-occupied properties qualify for better loan terms.", example: "Claiming a property as owner-occupied when you don't live there is mortgage fraud — lenders verify occupancy and the penalties are severe." },
    { term: "Occupancy Permit", definition: "A document issued by a local government certifying that a property meets all applicable building codes and is suitable for occupancy. Similar to a certificate of occupancy, often required before a new owner can move in.", example: "Some municipalities require the seller to obtain an occupancy permit before closing, which may involve a municipal inspection to verify code compliance." },
    { term: "Open House", definition: "A scheduled period during which a property for sale is open for public viewing without requiring individual appointments, allowing prospective buyers to tour the home.", example: "Open houses are a common marketing tool — attending several in your target neighborhood helps you understand local pricing and what's available before making an offer." },
    { term: "Option Period", definition: "A negotiated time frame (typically 5-14 days) during which the buyer has the unrestricted right to terminate the purchase contract for any reason, usually in exchange for a non-refundable option fee paid to the seller.", example: "In Texas, the option period gives buyers the right to cancel for any reason — use this time to complete inspections and negotiate repairs before your option expires." },
    { term: "Offer to Purchase", definition: "A formal written proposal from a buyer to a seller specifying the price, terms, and conditions under which the buyer is willing to buy the property. Also called a purchase offer or bid.", example: "Your offer to purchase should include the price, financing terms, contingencies, proposed closing date, and earnest money amount — your agent will help you structure a competitive offer." },
    { term: "Outstanding Balance", definition: "The remaining unpaid principal amount on a mortgage or other loan at any given point in time, not including future interest payments.", example: "Your monthly mortgage statement shows the outstanding balance — on a 30-year loan, you'll notice the balance drops slowly at first because most early payments go toward interest." },
  ],
  P: [
    { term: "Par Rate", definition: "The interest rate at which a lender offers a mortgage with no discount points and no lender credits — the baseline rate before any adjustments for points or credits.", example: "If the par rate is 6.5%, you can pay points to buy it down to 6.25%, or accept lender credits in exchange for a higher rate of 6.75%." },
    { term: "Parcel", definition: "A specific, legally defined piece of real estate identified by a unique parcel number assigned by the county tax assessor for taxation and identification purposes.", example: "Every property has a unique parcel number (also called APN or PIN) that the county uses for tax records, and your title company uses it to conduct the title search." },
    { term: "Partition", definition: "A legal proceeding to divide co-owned property among the owners when they cannot agree on its use or disposition. The court may order the property physically divided or sold.", example: "When siblings inherit a home and can't agree on whether to sell it, one can file a partition action asking the court to force a sale and divide the proceeds." },
    { term: "Personal Property Coverage", definition: "The portion of a homeowner's insurance policy that covers your belongings (furniture, electronics, clothing, appliances) against theft, damage, or destruction.", example: "Personal property coverage typically covers 50-70% of your dwelling coverage amount — create a home inventory to make sure it's enough to replace your belongings." },
    { term: "Piggyback Loan", definition: "A second mortgage taken out simultaneously with the first mortgage to avoid paying private mortgage insurance (PMI), typically structured as an 80-10-10 or 80-15-5.", example: "With an 80-10-10 piggyback loan, you get an 80% first mortgage, a 10% second mortgage (usually a HELOC), and put 10% down — avoiding PMI entirely." },
    { term: "PITI", definition: "Principal, Interest, Taxes, and Insurance — the four components of a typical monthly mortgage payment.", example: "Your total PITI payment includes the mortgage principal and interest, plus monthly escrow contributions for property taxes and homeowner's insurance." },
    { term: "Plat", definition: "A map drawn to scale showing the division of a piece of land into lots, blocks, streets, and common areas, recorded in the county records as the official map of a subdivision.", example: "The recorded plat map shows your property's exact lot dimensions, boundaries, setbacks, and easements within the subdivision." },
    { term: "PMI (Private Mortgage Insurance)", definition: "Insurance required on conventional loans when the borrower puts less than 20% down. Protects the lender if the borrower defaults. Can be removed once equity reaches 20%.", example: "PMI costs $50-$300/month depending on your loan amount and credit score. Once you reach 20% equity, you can request its removal — unlike FHA MIP." },
    { term: "Policy Jacket", definition: "The standard pre-printed terms and conditions that form part of every title insurance policy, containing the general provisions, definitions, exclusions, and conditions that apply.", example: "The policy jacket contains the fine print of your title insurance policy — the specific details of your coverage are in Schedule A and Schedule B." },
    { term: "Policy Limits", definition: "The maximum amount an insurance policy will pay for a covered loss. In homeowner's insurance, separate limits apply to dwelling, personal property, and liability coverage.", example: "Review your policy limits annually to make sure they keep up with construction costs — if your home would cost $400,000 to rebuild, your dwelling limit should reflect that." },
    { term: "Portfolio Loan", definition: "A mortgage that the lender keeps in its own investment portfolio rather than selling to Fannie Mae, Freddie Mac, or investors. This allows more flexible underwriting guidelines.", example: "A portfolio lender may approve a loan that doesn't meet conventional guidelines — useful for self-employed borrowers, unique properties, or complex financial situations." },
    { term: "Post-Closing", definition: "The period and activities that occur after the closing documents are signed, including recording the deed, disbursing funds, issuing title insurance policies, and resolving any remaining conditions.", example: "Post-closing tasks include recording the deed with the county, sending the final title policy, and ensuring all loan conditions are satisfied." },
    { term: "Power of Attorney (POA)", definition: "A legal document authorizing one person to act as another's agent in legal and financial matters, including signing closing documents.", example: "If you can't attend closing in person, a specific power of attorney can authorize someone to sign on your behalf — but your lender must approve the POA language in advance." },
    { term: "Pre-Approval", definition: "A lender's conditional commitment to lend a specific amount based on verified income, assets, credit, and employment. Stronger than pre-qualification.", example: "Pre-approval involves a full credit check and documentation review — sellers take pre-approved offers far more seriously than pre-qualified ones." },
    { term: "Pre-Closing", definition: "The period and activities leading up to the closing date, including finalizing documents, completing the title search, clearing conditions, and scheduling the closing.", example: "During the pre-closing phase, your lender sends final documents to the title company, and you complete your final walkthrough and arrange the wire transfer." },
    { term: "Preliminary Title Report", definition: "A report showing current property ownership, existing liens, easements, and encumbrances. Issued before the final title insurance policy.", example: "Review the preliminary title report carefully — it shows everything that will be excluded from your title insurance coverage (Schedule B exceptions)." },
    { term: "Prepaid Items", definition: "Expenses paid at closing that cover costs in advance, such as prepaid interest, the first year's homeowner's insurance premium, and initial property tax deposits.", example: "Prepaids at closing often include 3-6 months of property tax, 12 months of insurance premium, and daily interest from closing to month-end — often $3,000-$6,000." },
    { term: "Prepayment Penalty", definition: "A fee charged by some lenders if the borrower pays off the mortgage early, either through refinancing or selling the property.", example: "Most modern mortgages do NOT have prepayment penalties — but always check your Loan Estimate to confirm before signing." },
    { term: "Pre-Qualification", definition: "An informal estimate of how much a buyer might be able to borrow, based on unverified financial information provided by the borrower.", example: "Pre-qualification takes minutes and doesn't affect your credit, but it carries no weight with sellers — always get pre-approved instead." },
    { term: "Principal", definition: "The amount of money borrowed, or the portion of a monthly payment that reduces the outstanding loan balance (as opposed to interest, taxes, or insurance)." },
    { term: "Probate", definition: "The legal process of administering a deceased person's estate, including validating the will, paying debts, and distributing property to heirs. Probate can significantly delay the sale of inherited property.", example: "If the seller inherited the property but hasn't completed probate, the closing could be delayed months while the court processes the estate." },
    { term: "Pro Forma", definition: "A preliminary or projected document showing estimated figures. In title insurance, a pro forma policy is a draft version showing what the final policy will look like.", example: "Your lender may request a pro forma title policy before closing to review the proposed coverage, exceptions, and endorsements." },
    { term: "Promissory Note", definition: "A written promise to pay a specified sum at a stated time. In real estate, it's the borrower's personal obligation to repay the mortgage.", example: "Unlike the deed of trust (which is tied to the property), the promissory note is YOUR personal obligation — you owe the money regardless of what happens to the property." },
    { term: "Property Tax", definition: "A tax assessed by local government based on a property's assessed value. Used to fund schools, roads, emergency services, and other public services.", example: "Property taxes vary dramatically by location — from 0.28% in Hawaii to 2.49% in New Jersey. On a $350K home, that's $980 vs. $8,715 per year." },
    { term: "Proration", definition: "The allocation of property expenses (taxes, HOA dues, utilities) between buyer and seller based on the closing date.", example: "If the seller already paid the full year's property tax and you close on July 1, the seller is entitled to a credit for the unused 6 months." },
    { term: "Public Records", definition: "Official records maintained by a county recorder's office containing transcriptions of all recorded instruments affecting real property — deeds, mortgages, liens, easements, and more." },
    { term: "PUD (Planned Unit Development)", definition: "A type of residential development that combines single-family homes, townhomes, or other housing types with shared common areas and amenities, governed by a homeowners association.", example: "A PUD differs from a condo in that you own the land beneath your home plus shared ownership of common areas — your lender will need a PUD rider for the mortgage." },
    { term: "Purchase Agreement", definition: "A legally binding contract between buyer and seller that outlines the terms and conditions of a real estate sale, including price, contingencies, closing date, and what's included.", example: "The purchase agreement is the most important document in the transaction — every term, deadline, and contingency must be clearly spelled out before you sign." },
    { term: "Purchase Money Mortgage", definition: "A mortgage provided by the seller to the buyer as part of the purchase transaction, where the seller acts as the lender and finances part or all of the purchase price.", example: "In a purchase money mortgage, the seller lets you finance $50,000 of the price directly with them — this can help bridge a gap when traditional financing falls short." },
    { term: "Pest Inspection", definition: "A professional inspection of a property for wood-destroying organisms such as termites, carpenter ants, and wood-boring beetles, as well as evidence of dry rot or fungus damage.", example: "Many lenders — especially for VA and FHA loans — require a clear pest inspection before closing. Treatment for active termites typically costs $500-$2,500 depending on severity." },
    { term: "Planned Community", definition: "A residential development with shared amenities, common areas, and an established homeowners association that enforces community standards through covenants, conditions, and restrictions (CC&Rs).", example: "Planned communities often include amenities like pools, trails, and clubhouses funded by monthly HOA dues — review the CC&Rs and financials before buying to understand your obligations." },
  ],
  Q: [
    { term: "Qualified Mortgage (QM)", definition: "A category of mortgage that meets specific standards set by the Consumer Financial Protection Bureau, including limits on fees, loan features, and debt-to-income ratios, providing certain legal protections to lenders.", example: "Most conventional, FHA, and VA loans are qualified mortgages — they prohibit risky features like negative amortization, interest-only periods over 10 years, and terms over 30 years." },
    { term: "Quiet Title Action", definition: "A lawsuit filed to establish clear ownership of a property by eliminating or 'quieting' any competing claims or clouds on the title.", example: "If the title search reveals a 100-year-old claim from an unknown heir, a quiet title action can legally resolve it — title insurance covers the legal costs." },
    { term: "Quitclaim Deed", definition: "A deed that transfers whatever interest the grantor may have in a property without making any warranties about the quality of that title.", example: "Quitclaim deeds are common between family members or divorcing spouses — but they offer zero title protection, so never accept one from a stranger." },
  ],
  R: [
    { term: "Rate Cap", definition: "The maximum amount an adjustable-rate mortgage's interest rate can increase during a single adjustment period or over the full life of the loan.", example: "A rate cap of 2/2/6 means your rate can't increase more than 2% on the first adjustment, 2% on subsequent adjustments, or more than 6% total over the life of the loan." },
    { term: "Rate Lock", definition: "A lender's commitment to hold a specific interest rate and points for a defined period, protecting the borrower from rate increases before closing." },
    { term: "Raw Land", definition: "Undeveloped land with no improvements, utilities, roads, or structures. Raw land typically requires significant investment before it can be built upon.", example: "Financing raw land is more difficult than developed lots — lenders see it as higher risk, so expect to put 20-50% down and pay higher interest rates." },
    { term: "Real Estate Settlement Procedures Act (RESPA)", definition: "A federal law that requires lenders to provide borrowers with disclosures about settlement costs, prohibits kickbacks between settlement service providers, and limits escrow account requirements.", example: "Under RESPA, no one can receive a referral fee for sending you to a specific title company, and your lender must disclose all settlement costs upfront." },
    { term: "Real Property", definition: "Land and anything permanently attached to it — buildings, fences, landscaping, and fixtures. Distinguished from personal property (movable items)." },
    { term: "Recasting", definition: "A mortgage recast recalculates your monthly payment based on the current remaining balance and original loan term after a large lump-sum payment toward principal, without changing the interest rate or loan term.", example: "After receiving a $50,000 inheritance and paying it toward your $300,000 mortgage, a recast reduces your monthly payment based on the new $250,000 balance — typically for a $250 processing fee." },
    { term: "Recording", definition: "Filing a document in the public records at the county recorder's office to provide constructive notice of the transaction to the public.", example: "After closing, the deed is recorded with the county — this is what officially makes you the owner of record." },
    { term: "Refinance", definition: "Replacing an existing mortgage with a new one, typically to obtain a lower interest rate, change the loan term, or access home equity (cash-out refinance).", example: "If rates drop 1% below your current rate, refinancing a $300,000 mortgage could save you $180/month or $64,800 over the remaining term." },
    { term: "Refinance Rate", definition: "A reduced title insurance premium available when refinancing, since the title company already has a recent search on file for the property." },
    { term: "Regulation Z", definition: "The federal regulation that implements the Truth in Lending Act, requiring lenders to disclose the true cost of credit to consumers, including the APR, finance charges, and total payments.", example: "Regulation Z is why your Loan Estimate includes the APR, total interest, and total payments — it ensures you know the full cost of borrowing before you commit." },
    { term: "Re-Inspection Fee", definition: "A fee charged by the appraiser to return to the property and verify that required repairs or conditions have been completed satisfactorily.", example: "If the appraiser noted a leaking roof that needed repair, the lender may require a re-inspection ($100-$200) to confirm the repair was completed before closing." },
    { term: "Remote Online Notarization (RON)", definition: "A technology-enabled process allowing a notary public to notarize documents via live audio-video communication. Available in 45 states and DC as of 2026, with ALTA and MBA leading advocacy efforts.", example: "With RON, you can complete your entire closing from your living room via secure video call — the session is recorded for security." },
    { term: "Renovation Loan", definition: "A mortgage product that finances both the purchase of a home and the cost of renovations in a single loan, such as the FHA 203(k) or Fannie Mae HomeStyle loan.", example: "An FHA 203(k) renovation loan lets you buy a fixer-upper for $250,000 and finance $75,000 in repairs in one mortgage, avoiding a separate construction loan." },
    { term: "Replacement Cost", definition: "The amount it would cost to rebuild or replace your home or belongings at current prices, without deducting for depreciation. Provides higher payouts than actual cash value coverage.", example: "Replacement cost coverage pays to rebuild your destroyed home at today's construction costs — if a 2,000 sq. ft. home costs $200/sq. ft. to rebuild, that's $400,000 regardless of what you originally paid." },
    { term: "Rescission", definition: "The cancellation or reversal of a contract, returning all parties to their original positions. In mortgage lending, federal law provides a right of rescission for certain refinance transactions.", example: "Under the Truth in Lending Act, you have a 3-day right of rescission on a refinance of your primary residence — you can cancel for any reason within that window." },
    { term: "Reserves", definition: "Liquid assets (savings, investments, retirement funds) that a borrower must have remaining after closing, measured in months of mortgage payments. Lenders require reserves to ensure the borrower can handle unexpected expenses.", example: "Your lender requires 2 months of reserves — with a $2,500 PITI payment, you need at least $5,000 in liquid assets remaining after paying your down payment and closing costs." },
    { term: "RESPA", definition: "Real Estate Settlement Procedures Act — a federal law that requires lenders to provide borrowers with disclosures about settlement costs, prohibits kickbacks, and gives buyers the right to choose their own title company.", example: "Under RESPA, no one can require you to use a specific title company — you have the legal right to shop for your own, which can save hundreds." },
    { term: "Reverse Mortgage", definition: "A loan available to homeowners aged 62 or older that allows them to convert home equity into cash payments without selling the home or making monthly mortgage payments. The loan is repaid when the borrower moves, sells, or passes away.", example: "A reverse mortgage lets a retiree tap $150,000 in home equity as monthly income or a lump sum, with no payments due until they move out — but it reduces the inheritance for heirs." },
    { term: "Rider", definition: "An addition or amendment to an insurance policy that modifies coverage, adding protection for specific items or situations not covered by the standard policy.", example: "If you have a $10,000 engagement ring, a jewelry rider on your homeowner's policy provides specific coverage beyond the standard $1,500 limit for valuables." },
    { term: "Right of First Refusal", definition: "A contractual right that gives a party the first opportunity to purchase a property or match any offer before the owner can sell to someone else.", example: "An HOA with right of first refusal can match a buyer's offer and purchase the unit itself — this is common in co-ops and some condo associations." },
    { term: "Right of Way", definition: "The right to pass over another person's property, or the strip of land dedicated for roads, utilities, sidewalks, or other access purposes." },
    { term: "Run Sheet", definition: "A document used by the title company to organize and summarize all recorded instruments affecting a property in chronological order, serving as a working tool during the title examination.", example: "The title examiner creates a run sheet listing every deed, mortgage, lien, and judgment recorded against the property, making it easy to track the chain of title." },
    { term: "Radon", definition: "A naturally occurring radioactive gas that can seep into homes through cracks in the foundation, posing health risks at elevated levels. Radon testing is a common part of the home inspection process.", example: "Radon levels above 4 pCi/L are considered actionable by the EPA — a radon mitigation system costs $800-$1,500 and effectively reduces levels in most homes." },
    { term: "Real Estate Agent", definition: "A licensed professional who represents buyers or sellers in real estate transactions, helping with property searches, negotiations, paperwork, and closing.", example: "A good real estate agent knows the local market, negotiates effectively, and guides you through the complex closing process — interview at least 2-3 agents before choosing one." },
    { term: "Reissue Rate", definition: "A discounted title insurance premium offered when a previous title insurance policy exists on the property, typically available if the prior policy was issued within the last 10 years.", example: "Ask your title company about the reissue rate — if the seller purchased title insurance when they bought the home, you may save 20-40% on your owner's policy premium." },
    { term: "Right of Survivorship", definition: "A legal right associated with joint tenancy and tenancy by the entirety that automatically transfers a deceased owner's share of the property to the surviving co-owner(s) without going through probate.", example: "With right of survivorship, when one spouse dies, the surviving spouse automatically becomes the sole owner of the property — no probate required, which saves time and legal fees." },
    { term: "Rent-Back Agreement", definition: "An arrangement where the seller remains in the property after closing as a tenant for a negotiated period, paying rent to the new owner. Also called a post-closing occupancy agreement or leaseback.", example: "A rent-back agreement allowed the sellers to stay in the home for 30 days after closing while their new house was being completed, paying the buyers $100/day in rent." },
  ],
  S: [
    { term: "Safe Act", definition: "The Secure and Fair Enforcement for Mortgage Licensing Act — a federal law requiring mortgage loan originators to be licensed or registered, pass background checks, and complete continuing education.", example: "Under the SAFE Act, you can verify your loan officer's license and check for disciplinary actions on the NMLS Consumer Access website." },
    { term: "Schedule A", definition: "The section of a title commitment that lists the proposed policy details: the parties involved, purchase price, legal description, and type of policy to be issued." },
    { term: "Schedule B", definition: "The section of a title commitment that lists exceptions — specific items the title insurance policy will NOT cover. Must be reviewed carefully before closing.", example: "Schedule B might list utility easements, HOA covenants, and mineral rights reservations — anything listed here is excluded from your coverage." },
    { term: "Scheduled Property", definition: "Specific high-value items individually listed on a homeowner's insurance policy with their own coverage amounts, providing broader protection than standard personal property coverage.", example: "Schedule your engagement ring, art collection, and high-end electronics individually on your policy to ensure full coverage if they're stolen or damaged." },
    { term: "Search", definition: "A thorough inspection and examination of public records to find all recorded instruments that affect the title to a specific property." },
    { term: "Seasoning", definition: "The length of time a borrower has held a mortgage, owned a property, or held funds in an account. Lenders often require seasoning periods before allowing certain transactions.", example: "Many lenders require 6-12 months of seasoning before you can refinance, and FHA requires down payment funds to be in your account for at least 60 days." },
    { term: "Secure Act", definition: "Legislation affecting retirement accounts that changed required minimum distribution rules and allows penalty-free withdrawals for certain purposes including first-time home purchases (up to $10,000 from IRAs).", example: "Under the SECURE Act, first-time homebuyers can withdraw up to $10,000 from an IRA penalty-free for a home purchase, though income taxes still apply." },
    { term: "Seller Concessions", definition: "Contributions from the seller toward the buyer's closing costs. Limited by loan type: conventional (3-9%), FHA (6%), VA (4%).", example: "Negotiating 3% seller concessions on a $350K home means the seller pays $10,500 of your closing costs — reducing the cash you need at closing." },
    { term: "Setback", definition: "The minimum distance a building or structure must be set back from the property line, street, or other boundary as required by local zoning regulations.", example: "If zoning requires a 25-foot front setback and 10-foot side setbacks, your buildable area is smaller than the total lot — verify setbacks before planning additions." },
    { term: "Settlement", definition: "Also called 'closing' — the final step in completing a real estate transaction where documents are signed, funds disbursed, and ownership transferred." },
    { term: "Settlement Agent", definition: "The person or company responsible for conducting the closing — coordinating documents, collecting and disbursing funds, and recording the deed." },
    { term: "Short Sale", definition: "The sale of a property for less than the amount owed on the mortgage, with the lender's agreement to accept the reduced payoff. Used as an alternative to foreclosure when the homeowner can no longer make payments.", example: "In a short sale, if you owe $350,000 but the home is only worth $280,000, the lender agrees to accept $280,000 and forgive the remaining $70,000 balance." },
    { term: "Simultaneous Issue Rate", definition: "A discounted rate for purchasing both an owner's and lender's title insurance policy from the same company at the same time.", example: "Ask about the simultaneous issue rate — buying both policies together typically saves 40-60% on the lender's policy premium." },
    { term: "Special Warranty Deed", definition: "A deed that warrants title only against claims arising during the seller's period of ownership, not against prior claims." },
    { term: "Spread", definition: "The difference between two interest rates, such as the difference between the rate a bank pays on deposits and the rate it charges on loans, or the difference between a benchmark rate and a mortgage rate.", example: "If the 10-year Treasury yield is 4% and mortgage rates are 6.5%, the spread is 2.5% — historically this spread has averaged about 1.7%, so a wider spread may signal rates will come down." },
    { term: "Starter (Title)", definition: "A copy of a previously issued title insurance policy or title report on a property, used as a starting point for a new title search, often making the process faster and less expensive.", example: "If you're refinancing, provide the title company with a copy of your existing policy as a starter — it speeds up the new search and may qualify you for a reduced rate." },
    { term: "Statute of Limitations", definition: "The maximum time period within which a legal action can be filed. In real estate, statutes of limitations vary by state and type of claim.", example: "If a contractor's defective work wasn't discovered until 5 years later, you may still have a claim if your state's statute of limitations for construction defects is 6 years." },
    { term: "Streamline Refinance", definition: "A simplified refinancing process with reduced documentation and underwriting requirements, available for FHA (FHA Streamline) and VA (IRRRL) loans.", example: "An FHA Streamline refinance requires no appraisal, no income verification, and minimal paperwork — making it the fastest way to lower your FHA loan's interest rate." },
    { term: "Subdivision", definition: "A tract of land divided into individual lots for sale or development, with streets, utilities, and common areas, typically governed by recorded covenants and an HOA.", example: "When buying in a subdivision, review the CC&Rs (covenants, conditions, and restrictions) to understand what rules govern the property before you commit." },
    { term: "Subordination", definition: "The process of changing the priority of a lien or mortgage, placing it behind another lien. A subordination agreement makes one lien junior to another.", example: "If you refinance your first mortgage while having a HELOC, the HELOC lender must sign a subordination agreement to keep the new first mortgage in priority position." },
    { term: "Subrogation", definition: "The right of an insurer who has paid a claim to step into the shoes of the insured and pursue recovery from the party that caused the loss.", example: "If your title insurer pays you $50,000 for a title defect caused by a prior owner's fraud, the insurer can then sue that person to recover the $50,000 through subrogation." },
    { term: "Supplemental Search", definition: "An additional title search conducted after the original search to check for any new recordings or changes that may have occurred since the initial examination.", example: "Before issuing the final title policy, the title company performs a supplemental search to catch any liens or claims filed since the original title commitment was issued." },
    { term: "Survey", definition: "A professional measurement and mapping of a property's exact boundaries, area, and location of structures, easements, and encroachments.", example: "A survey costs $300-$800 and reveals whether your fences, driveways, or structures cross property lines — critical information before you buy." },
    { term: "Seller's Market", definition: "A real estate market condition where there are more buyers than available homes, giving sellers the advantage in negotiations on price and terms.", example: "In a seller's market with less than 3 months of inventory, expect multiple offers, bidding wars, and less room to negotiate on price or contingencies." },
    { term: "Seller Financing", definition: "An arrangement where the property seller provides financing to the buyer instead of or in addition to a traditional mortgage from a bank or lender.", example: "Seller financing can help buyers who don't qualify for traditional loans, but typically comes with higher interest rates and shorter terms than conventional mortgages." },
    { term: "Special Assessment", definition: "An additional charge levied by an HOA or local government for specific improvements or unexpected expenses beyond what regular dues or taxes cover.", example: "Your condo HOA might impose a $5,000 special assessment for a new roof — check the HOA meeting minutes and financial statements before buying to see if any are planned." },
    { term: "Satisfaction of Mortgage", definition: "A document recorded in public records when a mortgage has been paid in full, releasing the lender's lien on the property.", example: "After you make your final mortgage payment, the lender files a satisfaction of mortgage — if they don't, it creates a cloud on title you'll need to resolve before selling." },
    { term: "Sewer Lateral", definition: "The underground pipe that connects a building's plumbing system to the public sewer main, typically running from the house to the street. The property owner is usually responsible for its maintenance and repair.", example: "A sewer lateral inspection ($100-$300) uses a camera to check for cracks, root intrusion, or collapse — replacing a failed sewer lateral can cost $5,000-$15,000." },
    { term: "Sinking Fund", definition: "A reserve fund set aside by a homeowners association for future major repairs and capital improvements, such as roof replacement, repaving, or elevator modernization.", example: "A well-funded sinking fund means the HOA has planned ahead for major expenses — a low or nonexistent sinking fund is a red flag that special assessments may be coming." },
  ],
  T: [
    { term: "Table Funding", definition: "A closing method where the loan is funded by the lender at the closing table (or the same day as closing), with the documents and funds handled simultaneously.", example: "In a table funding transaction, the lender wires funds to the title company on closing day so the borrower, seller, and lender all complete the transaction at once." },
    { term: "Tax Certificate", definition: "A document from the county tax collector confirming the current status of property taxes — whether they are paid, unpaid, or delinquent — and the amounts due.", example: "The title company orders a tax certificate to verify the seller is current on property taxes and to calculate the correct proration between buyer and seller at closing." },
    { term: "Tax Lien", definition: "A legal claim placed on property by a government entity for unpaid taxes. Tax liens take priority over most other liens, including mortgages." },
    { term: "Teaser Rate", definition: "A temporarily low introductory interest rate on an adjustable-rate mortgage that is below the fully indexed rate, used to attract borrowers. The rate increases after the introductory period ends.", example: "A teaser rate of 4% on an ARM may jump to 7%+ after the first year — always calculate what your payment would be at the fully indexed rate before committing." },
    { term: "Tenants in Common", definition: "A form of co-ownership where two or more persons hold separate, undivided interests in a property with no right of survivorship — each owner's share passes to their heirs, not the other owners." },
    { term: "Three-Day Right of Rescission", definition: "A federal right under the Truth in Lending Act that allows borrowers to cancel certain mortgage transactions (primarily refinances of a primary residence) within three business days of closing, for any reason.", example: "After signing your refinance documents, you have until midnight on the third business day to cancel the deal — no explanation needed. This does NOT apply to purchase mortgages." },
    { term: "TILA", definition: "Truth in Lending Act — a federal law requiring lenders to clearly disclose the APR, total interest cost, and all loan terms so borrowers can make informed decisions.", example: "TILA is why your Loan Estimate shows the APR alongside the interest rate — it forces lenders to reveal the true total cost of borrowing." },
    { term: "Timeshare", definition: "A form of shared property ownership where multiple buyers purchase the right to use a vacation property for a specific period each year.", example: "Timeshares can be difficult to resell and often lose value — carefully consider the long-term costs including annual maintenance fees before committing." },
    { term: "Title", definition: "The legal right to ownership of real property, including the right to possess, use, and dispose of the property. Title is evidenced by a deed." },
    { term: "Title Commitment", definition: "A document issued by the title company offering to issue a title insurance policy, subject to specified requirements, exceptions, and exclusions.", example: "Review your title commitment carefully — especially Schedule B, which lists what your policy WON'T cover." },
    { term: "Title Company", definition: "A company that searches property records, issues title insurance, and often serves as the closing agent for real estate transactions." },
    { term: "Title Defect", definition: "Any outstanding claim, lien, irregularity, or document error that could impair the owner's title or create doubt about ownership." },
    { term: "Title Insurance", definition: "Insurance protecting property purchasers and lenders against financial loss from defects in title, liens, and encumbrances that were not known at the time of closing.", example: "Unlike other insurance that protects against future events, title insurance protects against past events — hidden problems that already exist but weren't discovered." },
    { term: "Title Search", definition: "A thorough review of public records — often spanning decades — to determine the status and history of a property's ownership, liens, easements, and encumbrances.", example: "Title searches reveal issues in approximately 1 in 3 transactions — unpaid liens, errors in public records, missing heirs, and other problems that must be resolved before closing." },
    { term: "Tort", definition: "A wrongful act or violation of a legal duty (other than a breach of contract) that causes harm or loss to another person, potentially resulting in civil liability.", example: "If a seller deliberately conceals a known foundation defect, the buyer may have a tort claim for fraud or misrepresentation in addition to any contract remedies." },
    { term: "Township", definition: "A unit of land measurement used in the government survey system, typically a 6-mile-by-6-mile square (36 square miles) containing 36 sections of one square mile each.", example: "In the government survey system, your property's legal description might reference a specific township, range, and section to identify its exact location." },
    { term: "Tract", definition: "A defined area or parcel of land, often referring to a large piece of land that may be subdivided into smaller lots for development.", example: "The developer purchased a 200-acre tract and subdivided it into 150 residential lots, creating a new housing community." },
    { term: "Transfer Tax", definition: "A tax imposed by state or local government when real property is transferred from one owner to another, typically calculated as a percentage of the sale price or a flat rate per dollar of consideration.", example: "Transfer tax rates vary widely — some states charge nothing, while others charge 1-2% of the sale price. On a $400,000 home, that could be $0 to $8,000." },
    { term: "TRID", definition: "TILA-RESPA Integrated Disclosure rule — a 2015 CFPB regulation that combined older disclosure forms into the standardized Loan Estimate and Closing Disclosure used today.", example: "Under TRID, your lender must provide a Loan Estimate within 3 business days of application and a Closing Disclosure at least 3 business days before closing." },
    { term: "Trust Account", definition: "An account held by a title company, attorney, or broker in which funds are held in trust for the parties to a real estate transaction." },
    { term: "Trustee", definition: "A person or entity that holds and manages property or assets for the benefit of another party (the beneficiary). In a deed of trust, the trustee holds the property title until the loan is repaid.", example: "In a deed of trust state, the trustee holds legal title to your property as security for the lender until you pay off the mortgage in full." },
    { term: "Truth in Lending Act (TILA)", definition: "A federal law enacted in 1968 that requires lenders to provide clear and standardized disclosure of loan costs and terms, enabling consumers to compare credit offers and make informed borrowing decisions.", example: "The Truth in Lending Act is why every mortgage lender must disclose the same information in the same format — making it easy to compare APRs, total interest, and monthly payments across lenders." },
    { term: "Title Abstract", definition: "A condensed history of all recorded documents and proceedings that affect the title to a specific parcel of real property.", example: "The title abstract traces ownership back decades and documents every transfer, lien, and encumbrance — it forms the basis for the title insurance commitment." },
    { term: "Title Exam", definition: "A thorough review and legal analysis of the title abstract and public records by a title examiner or attorney to identify any defects, liens, or issues affecting ownership.", example: "The title exam takes 1-2 weeks and reviews decades of records — if the examiner finds issues, they must be resolved before the title company will insure the property." },
    { term: "Townhouse", definition: "A multi-story residential unit that shares one or more walls with adjacent units but has its own entrance, and where the owner typically owns the land beneath the unit.", example: "Townhouses are often more affordable than single-family homes and offer more space than condos — you own the structure and the land, but share walls with neighbors." },
    { term: "Title Plant", definition: "A comprehensive, organized collection of title records maintained by a title company, indexed by property, to efficiently search titles without going to the county recorder each time.", example: "Title companies with their own title plant can complete title searches faster because all records are organized in their own database." },
    { term: "Title Vesting", definition: "The legal manner in which a property owner holds title, specifying the form of ownership such as sole ownership, joint tenancy, tenants in common, or trust.", example: "How you vest title has major legal and tax implications — joint tenancy provides automatic survivorship rights, while tenants in common allows unequal shares." },
    { term: "Title Opinion", definition: "A written statement by an attorney expressing a legal opinion on the status of a property's title based on a review of the abstract or title search, identifying any defects, liens, or encumbrances.", example: "In some states, an attorney's title opinion serves as the basis for issuing title insurance — the attorney examines the records and certifies the title's status." },
    { term: "Tax Abatement", definition: "A reduction or elimination of property taxes for a specified period, often offered by local governments as an incentive for new construction, renovation, or development in targeted areas.", example: "A 10-year tax abatement on a new condo means you pay reduced property taxes for the first decade — but budget for the full tax amount once the abatement expires." },
  ],
  U: [
    { term: "Umbrella Policy", definition: "An insurance policy that provides additional liability coverage beyond the limits of your homeowner's, auto, or other underlying policies, typically in increments of $1 million.", example: "An umbrella policy costing $200-$400/year adds $1 million in liability coverage above your homeowner's and auto policies — essential if you have significant assets to protect." },
    { term: "Underwater Mortgage", definition: "A situation where the outstanding mortgage balance exceeds the current market value of the property, also known as being 'upside down' on the loan.", example: "If you owe $320,000 but your home is only worth $280,000, you're $40,000 underwater — which makes it difficult to refinance or sell without bringing cash to closing." },
    { term: "Underwriting", definition: "The lender's formal process of evaluating a borrower's creditworthiness, income, assets, and the property's value to determine whether to approve the loan.", example: "During underwriting, the lender verifies everything: W-2s, tax returns, bank statements, employment, credit history, and the appraisal. Do NOT make large purchases or change jobs during this period." },
    { term: "Underwriter", definition: "The person or company that evaluates and assumes the risk of insuring a title or mortgage. In title insurance, the underwriter issues the policy." },
    { term: "Update (Title)", definition: "A supplemental title search conducted to extend a previous title examination from its effective date to the current date, checking for new recordings.", example: "If your closing is delayed by two months, the title company will order an update to the title search to make sure nothing new has been recorded against the property." },
    { term: "USDA Loan", definition: "A zero-down-payment mortgage program for properties in eligible rural and suburban areas, backed by the U.S. Department of Agriculture. Requires a guarantee fee instead of PMI.", example: "USDA loans have no down payment requirement and lower guarantee fees than FHA — check the USDA eligibility map, as many suburban areas qualify." },
    { term: "Usury", definition: "Charging interest on a loan at a rate that exceeds the maximum allowed by state law. Usury laws vary by state and are designed to protect borrowers from predatory lending.", example: "If your state caps mortgage interest at 18% and a lender charges 20%, the loan may be deemed usurious and the lender could face penalties or the excess interest could be voided." },
    { term: "Utility Easement", definition: "A legal right granted to utility companies to access, install, maintain, or repair utility infrastructure (power lines, water pipes, gas lines) on private property.", example: "A utility easement along the side of your property means you can't build a structure there — the power company needs permanent access to maintain their lines." },
    { term: "Unimproved Land", definition: "Land that has no buildings, structures, or site improvements such as roads, utilities, or grading. Similar to raw land but may have some basic infrastructure nearby.", example: "Unimproved land is typically cheaper to buy but more expensive to develop — factor in the cost of running utilities, grading, and building a driveway before purchasing." },
    { term: "Uniform Residential Loan Application (URLA)", definition: "The standardized mortgage application form (Fannie Mae Form 1003/Freddie Mac Form 65) used by virtually all lenders to collect borrower information including income, assets, debts, and property details.", example: "The URLA is the form you complete when applying for a mortgage — it asks for detailed information about your employment, income, assets, debts, and the property you're buying." },
  ],
  V: [
    { term: "VA Entitlement", definition: "The amount the VA guarantees on a veteran's home loan, which determines the maximum loan amount available without a down payment. Veterans have both basic and bonus entitlement.", example: "Full VA entitlement allows you to buy a home at any price with $0 down, while partial entitlement (if you already have a VA loan) may limit the zero-down amount." },
    { term: "VA Loan", definition: "A mortgage program for active-duty military, veterans, National Guard/Reserves, and eligible surviving spouses, guaranteed by the U.S. Department of Veterans Affairs. No down payment or monthly mortgage insurance required.", example: "VA loans are one of the best mortgage products available — 0% down, no PMI, competitive rates, and no prepayment penalty." },
    { term: "Vacant Land", definition: "Land that is unoccupied and unused, which may or may not have utilities, roads, or other infrastructure available. Different from raw land, which has no improvements at all.", example: "Buying vacant land with utilities already available at the lot line is less expensive to develop than raw land where you'd need to run water, sewer, and electric lines." },
    { term: "Variance", definition: "Permission granted by a local government to deviate from zoning requirements for a specific property, such as building closer to the property line than normally allowed." },
    { term: "Vest", definition: "To give a person an immediate right to present or future possession or enjoyment of property. When title is vested, the owner has a confirmed legal right to the property.", example: "Title vests in the new owner when the deed is recorded — at that point, you have confirmed legal ownership of the property." },
    { term: "Vesting", definition: "The manner in which ownership title is held — methods include sole ownership, joint tenancy, tenants in common, community property, and trust ownership.", example: "How you take title (vesting) affects inheritance, taxes, and liability — discuss with an attorney before closing, especially if buying with a partner." },
    { term: "Void", definition: "Having no legal force or effect. A void contract or deed is invalid from the beginning and cannot be enforced by either party.", example: "A deed signed by someone who was not the legal owner is void — it has no legal effect and cannot transfer title, regardless of what the parties intended." },
    { term: "Voidable", definition: "A contract or deed that is valid until one party takes action to void it, typically due to fraud, duress, undue influence, or incapacity.", example: "A contract signed under duress is voidable — it remains valid unless the affected party chooses to void it within the applicable time period." },
    { term: "Volume", definition: "A bound book of recorded documents maintained by the county recorder's office. Documents are identified by their volume (or book) and page number for reference.", example: "Your deed might be recorded as 'Volume 1247, Page 342' at the county recorder's office — these reference numbers make it easy to locate any recorded document." },
    { term: "Vendee", definition: "The buyer or purchaser in a real estate transaction. The counterpart to the vendor (seller).", example: "In legal documents and contracts, you may see the buyer referred to as the vendee and the seller as the vendor — these are formal terms for the same parties." },
  ],
  W: [
    { term: "Waiver", definition: "The voluntary, intentional relinquishment of a known right, claim, or privilege." },
    { term: "Walk-Through", definition: "A final inspection of the property by the buyer, typically 24-48 hours before closing, to verify the property is in the agreed-upon condition and repairs have been completed.", example: "Turn on every faucet, flush every toilet, test every light switch — the walk-through is your last chance to catch problems before you sign." },
    { term: "Warranty Deed", definition: "A deed containing one or more title covenants guaranteeing clear title from the grantor to the grantee — the strongest form of deed protection for the buyer." },
    { term: "Wet Funding", definition: "A closing where the loan is funded and all funds are disbursed on the same day that closing documents are signed, as opposed to dry funding where disbursement occurs later.", example: "In wet funding states, you sign documents and the lender wires funds the same day — meaning you can get the keys and move in immediately after closing." },
    { term: "Wetlands", definition: "Areas of land where the soil is saturated with water either permanently or seasonally, subject to strict federal and state regulations that may limit or prohibit development.", example: "Before buying property with wetlands, check with the Army Corps of Engineers — wetlands regulations can severely restrict what you can build and may require expensive mitigation." },
    { term: "Wire Fraud", definition: "A scheme targeting real estate transactions where criminals use spoofed emails or hacked accounts to redirect closing funds to fraudulent accounts.", example: "Wire fraud cost homebuyers $275.1 million in 2025. ALWAYS verify wiring instructions by phone using a number you already have — never trust email alone." },
    { term: "Wire Transfer", definition: "An electronic transfer of funds from one bank account to another. The primary method for transferring closing funds, requiring verified instructions.", example: "Wire your closing funds 1-2 days before closing, but ONLY after verifying the account details by phone. Check your bank's cutoff time — many stop processing at 3 PM." },
    { term: "Wraparound Mortgage", definition: "A form of seller financing where the seller's existing mortgage remains in place and the buyer makes payments to the seller, who continues paying the original mortgage from those funds.", example: "In a wraparound mortgage, the seller keeps their 4% loan in place while financing the buyer at 6%, profiting from the 2% spread — but this may violate the due-on-sale clause." },
    { term: "Wood-Destroying Insect Report (WDI)", definition: "A formal inspection report documenting the presence or absence of termites, carpenter ants, powder post beetles, and other wood-destroying insects, often required by lenders before closing.", example: "VA loans require a clear WDI report — if the inspector finds evidence of active termites, treatment must be completed and a clearance letter obtained before the lender will fund the loan." },
  ],
  X: [
    { term: "X (Signature Mark)", definition: "A mark used in place of a signature by a person who is unable to write their name. In real estate documents, an X must typically be witnessed and notarized.", example: "If a seller cannot sign their name, they may use an X mark on the deed, but it must be witnessed by two people and acknowledged by a notary public." },
  ],
  Y: [
    { term: "Year Built", definition: "The year a property was originally constructed, as recorded in public records. Year built affects property value, insurance rates, and potential issues like lead paint or outdated systems.", example: "Homes built before 1978 may contain lead paint, those before 1980 may have asbestos, and those built before the 1990s may have polybutylene plumbing — year built helps you anticipate issues." },
    { term: "Yield", definition: "The return on an investment expressed as an annual percentage. In mortgage lending, yield refers to the lender's effective return on a loan after accounting for fees, points, and other factors.", example: "A lender's yield on a 6.5% mortgage may actually be higher after factoring in origination fees, PMI, and the likelihood the borrower refinances within 5-7 years." },
    { term: "Yield Spread Premium", definition: "A payment from a lender to a mortgage broker for delivering a loan with an interest rate above the par rate. Now largely regulated, it was a common practice that could increase borrowers' rates without their knowledge.", example: "Yield spread premiums are now disclosed and regulated under RESPA and Dodd-Frank — if your broker earns one, it must be clearly shown on your Closing Disclosure." },
    { term: "Year-End Statement", definition: "An annual summary provided by your mortgage servicer (Form 1098) showing the total interest paid, property taxes paid from escrow, and mortgage insurance premiums for the tax year, used for income tax deductions.", example: "Your year-end statement (Form 1098) arrives in January and shows the mortgage interest you paid — this amount is deductible on your federal tax return if you itemize." },
  ],
  Z: [
    { term: "Zero-Closing-Cost Mortgage", definition: "A mortgage where the lender covers all closing costs in exchange for a higher interest rate. No money is due at closing beyond the down payment, but the borrower pays more over the life of the loan.", example: "A zero-closing-cost mortgage might save you $8,000 at closing but cost you $15,000+ more in interest over 30 years — only beneficial if you plan to sell or refinance within a few years." },
    { term: "Zoning", definition: "Local government regulations that control how land in specific areas can be used — residential, commercial, industrial, agricultural, or mixed-use.", example: "Before buying, verify the property's zoning allows your intended use — you can't run a commercial business from a property zoned strictly residential." },
    { term: "Zoning Variance", definition: "A special exception granted by a local zoning board that allows a property owner to use their land in a way that deviates from the current zoning regulations.", example: "If you want to add a detached workshop in an area where zoning doesn't allow accessory structures, you'd need to apply for a zoning variance from the local board." },
    { term: "Zero-Lot-Line", definition: "A type of residential construction where a building is positioned on or very near the property boundary, maximizing usable yard space on one side. Common in townhomes and urban infill developments.", example: "In a zero-lot-line home, one wall of the house sits directly on the property line — you get a larger yard on the opposite side, but have little to no access along that wall." },
    { term: "Zone Change", definition: "A legislative act by a local government that officially changes the zoning classification of a parcel of land, such as from residential to commercial or from single-family to multi-family.", example: "A developer seeking a zone change from agricultural to residential must apply to the local planning commission and typically attend public hearings where neighbors can voice support or opposition." },
  ],
};
